	(28, 3, 'Reymon', 'LGU_ADMIN', 'Published training module', 'Training Modules', 'success', '127.0.0.1', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/149.0.0.0 Safari/537.36', 'http://127.0.0.1:8000/training-modules/5/publish', 'Title: Fire Safety and Emergency Response', NULL, '{"id":5,"title":"Fire Safety and Emergency Response","description":"This training module equips participants with the fundamental knowledge and practical skills needed to prevent, respond to, and safely evacuate during fire-related emergencies. Participants will learn fire prevention strategies, the proper use of fire extinguishers, emergency response procedures, and evacuation protocols applicable in homes, schools, workplaces, and government facilities.","learning_objectives":["Understand the basic principles of fire safety.","Identify the common causes of fire incidents.","Apply effective fire prevention practices.","Recognize the different types of fire extinguishers and their appropriate uses.","Demonstrate the proper PASS technique when operating a fire extinguisher.","Follow the correct emergency response and evacuation procedures during a fire incident."],"estimated_duration_minutes":60,"thumbnail_path":"training-module-thumbnails\\/5J7rKA7ACj0w5MUNtedpX4WTnWai5jc5vEhf2dXu.png","difficulty":"Intermediate","category":"Fire","status":"draft","visibility":"all","owner_id":3,"created_at":"2026-06-27T15:11:29.000000Z","updated_at":"2026-06-27T16:10:33.000000Z"}', '{"id":5,"title":"Fire Safety and Emergency Response","description":"This training module equips participants with the fundamental knowledge and practical skills needed to prevent, respond to, and safely evacuate during fire-related emergencies. Participants will learn fire prevention strategies, the proper use of fire extinguishers, emergency response procedures, and evacuation protocols applicable in homes, schools, workplaces, and government facilities.","learning_objectives":["Under