	(1, 5, NULL, 'Public Safety Campaign Management System', 'Fire Safety and Emergency Response - Session 1 • 2026-07-10 • 13:28 - 14:28', '2026-07-09 04:28:58', '2026-07-09 05:52:41', 'approved', 30, 20, 0, '{"id":5,"training_module_id":5,"training_title":"Fire Safety and Emergency Response","short_description":"This training module equips participants with the fundamental knowledge and practical skills needed to prevent, respond to, and safely evacuate during fire-related emergencies. Participants will learn fire prevention strategies, the proper use of fire extinguishers, emergency response procedures, and evacuation protocols applicable in homes, schools, workplaces, and government facilities.","related_hazards":"Fire","recommended_communities":{"summary":{"total_communities":3,"high_priority":1,"medium_priority":2,"low_priority":0},"communities":[{"barangay_profile_id":7,"barangay_name":"Holy Spirit","municipality_city":"Quezon City","province":"Metro Manila","related_hazard":"Fire","risk_level":"High","priority_level":"Priority 1","priority_score":72,"recommendation_reason":"Recommended due to high fire susceptibility.","recommendation":"Recommended due to high fire susceptibility."},{"barangay_profile_id":4,"barangay_name":"Commonwealth","municipality_city":"Quezon City","province":"Metro Manila","related_hazard":"Fire","risk_level":"Medium","priority_level":"Priority 2","priority_score":55,"recommendation_reason":"Recommended based on moderate fire exposure.","recommendation":"Recommended based on moderate fire exposure."},{"barangay_profile_id":6,"barangay_name":"Bagong Silangan","municipality_city":"Quezon City","province":"Metro Manila","related_hazard":"Fire","risk_level":"Medium","priority_level":"Priority 2","priority_score":48,"recommendation_reason":"Recommended based on moderate fire exposure.","recommendation":"Recommended based on moderate fire exposure."}]},"recommended_audience":null,"estimated_duration_minutes":60,"total_lessons":3,"assigned_trainers":[{"id":5,"name":"Reymon","role":"Trainer","specialization":"Fire Safety and Emergency Response","contact_email":"brogada.reymon09@gmail.com","status":"active","certifications":["LGU DRRM Trainer","Fire Safety Instructor"]}],"available_training_sessions":[{"title":"Fire Safety and Emergency Response - Session 1","date":"2026-07-10","start_time":"13:28","end_time":"14:28","delivery_method":"online","venue":"","online_platform":"google_meet","meeting_link":"https:\\/\\/workspace.google.com\\/products\\/meet\\/?utm_source=google&utm_medium=cpc&utm_campaign=1713702-Workspace-DR-APAC-PH-en-Google-BKWS-BRO-Hybrid-Others&utm_content=c-Hybrid+%7C+BKWS+-+BRO+%7C+Txt-Meet-N\\/A+1-297900019805&utm_term=google%20meet&gclsrc=aw.ds&gad_source=1&gad_campaignid=18195926841&gclid=CjwKCAjw6rfSBhAqEiwA_yocpowGRU-kH0T63lHwhYliKozeMpjXCnZooY_sSJqjQQH1PH9aDKP9MRoCdkUQAvD_BwE","maximum_participants":30}],"maximum_participants":[30],"additional_communities":[]}', NULL, '2026-07-09 04:28:58', '2026-07-09 05:52:41', 3);
