REPLACE INTO `evaluation_results` (`id`, `participant_id`, `training_module_id`, `ai_scenario_attempt_id`, `attempt_number`, `duration_seconds`, `scenario_title`, `difficulty`, `score`, `correct_answers`, `wrong_answers`, `total_questions`, `percentage`, `rating`, `status`, `knowledge_score`, `decision_making_score`, `emergency_response_score`, `safety_awareness_score`, `feedback`, `recommendations`, `generated_questions`, `participant_answers`, `eligible_for_simulation`, `completed_at`, `created_at`, `updated_at`) VALUES
	(1, 34, 5, 1, NULL, NULL, 'Emergency at Barangay Manggahan Multi-Purpose Hall', 'medium', 0, 0, 20, 20, 0.00, 1, 'needs_improvement', 1, 1, 1, 1, 'Your initial assessment on the Barangay Manggahan scenario quiz, while showing a 0% score, provides valuable insights into areas we can strengthen together for effective fire safety and emergency response. Specifically, focusing on core knowledge, rapid decision-making under pressure, practical emergency response protocols, and overall safety awareness will be key to your development in this module. We encourage you to thoroughly review the module content to build a solid foundation and confidence in these critical skills.', '["Retake AI Scenario Training","Review: Lesson 1: Introduction to Fire Safety","Review: Lesson 3: Fire Prevention"]', '[{"number":1,"competency":"knowledge","correct_answer":"C","question_en":"What is one of the most common hazards that can cause injuries, loss of life, and damage to property, as introduced in the Fire Safety module?","question_fil":"Ano ang isa sa mga pinakakaraniwang peligro na maaaring magdulot ng mga pinsala, pagkawala ng buhay, at pinsala sa ari-arian, ayon sa ipinakilala sa modyul ng Kaligtasan sa Sunog?","explanation_en":"Lesson 1, \'Introduction to Fire Safety,\' states that fire is one of the most common hazards.","explanation_fil":"Ang Aralin 1, \'Panimula sa Kaligtasan sa Sunog,\' ay nagsasaad na ang sunog ay isa sa mga pinakakaraniwang peligro.","choice_a_en":"Earthquakes","choice_a_fil":"Mga Lindol","choice_b_en":"Typhoons","choice_b_fil":"Mga Bagyo","choice_c_en":"Fires","choice_c_fil":"Mga Sunog","choice_d_en":"Landslides","choice_d_fil":"Mga Pagguho ng Lupa"},{"number":2,"competency":"safety_awareness","correct_answer":"B","question_en":"In the scenario, the presence of old chairs and tables partially obstructing the hall\'s exits primarily poses a risk by:","question_fil":"Sa sitwasyon, ang pagkakaroon ng mga lumang upuan at mesa na bahagyang nakaharang sa mga labasan ng bulwagan ay pangunahing nagdudulot ng panganib sa pamamagitan ng:","explanation_en":"Obstructions near exits directly impede the flow of people during an emergency evacuation, increasing danger and slowing response.","explanation_fil":"Ang mga harang malapit sa mga labasan ay direktang humahadlang sa pagdaloy ng mga tao sa panahon ng emerhensiyang paglikas, na nagpapataas ng panganib at nagpapabagal sa pagtugon.","choice_a_en":"Making the hall look untidy.","choice_a_fil":"Pagpapamukha sa bulwagan na hindi maayos.","choice_b_en":"Hindering efficient evacuation.","choice_b_fil":"Paghadlang sa epektibong paglikas.","choice_c_en":"Attracting pests and insects.","choice_c_fil":"Pag-akit ng mga peste at insekto.","choice_d_en":"Causing electrical overloads.","choice_d_fil":"Pagdulot ng electrical overloads."},{"number":3,"competency":"decision_making","correct_answer":"C","question_en":"Upon witnessing the electrical spark and initial flame, what should be Barangay Captain Reyes\' immediate priority action?","question_fil":"Sa pagkakita ng kuryenteng kislap at paunang apoy, ano ang dapat na agarang pangunahing aksyon ni Kapitan Reyes ng Barangay?","explanation_en":"The primary immediate action in a developing fire, especially with an audience, is to alert others and begin evacuation. Initial suppression should only be attempted if safe and trained.","explanation_fil":"Ang pangunahing agarang aksyon sa isang umuusbong na sunog, lalo na kung may mga tao, ay alertuhin ang iba at simulan ang paglikas. Ang paunang pagsugpo ay dapat lamang subukan kung ligtas at may sapat na pagsasanay.","choice_a_en":"Attempt to put out the fire with a bucket of water.","choice_a_fil":"Subukang patayin ang apoy gamit ang isang timba ng tubig.","choice_b_en":"Direct attendees to remain seated calmly.","choice_b_fil":"Utusan ang mga dumalo na manatiling nakaupo nang mahinahon.","choice_c_en":"Initiate the fire alarm and announce evacuation.","choice_c_fil":"Pindutin ang fire alarm at ipahayag ang paglikas.","choice_d_en":"Call his family to inform them of the situation.","choice_d_fil":"Tumawag sa kanyang pamilya upang ipaalam ang sitwasyon."},{"number":4,"competency":"emergency_response","correct_answer":"C","question_en":"Considering the fire originated from an electrical source (air conditioning unit), which type of fire extinguisher would be most appropriate to attempt initial suppression, if it were deemed safe to do so?","question_fil":"Isinasaalang-alang na ang sunog ay nagmula sa isang electrical na pinagmulan (air conditioning unit), anong uri ng fire extinguisher ang pinakaangkop na gamitin para sa paunang pagsugpo, kung ito ay itinuring na ligtas gawin?","explanation_en":"Electrical fires are Class C fires. Water and foam are conductive and dangerous for electrical fires. CO2 or dry chemical extinguishers are suitable for Class C fires.","explanation_fil":"Ang mga sunog na electrical ay Klase C. Ang tubig at foam ay conductive at mapanganib para sa mga electrical na sunog. Ang CO2 o dry chemical extinguishers ay angkop para sa mga sunog na Klase C.","choice_a_en":"Water extinguisher (Class A)","choice_a_fil":"Water extinguisher (Klase A)","choice_b_en":"Foam extinguisher (Class A and B)","choice_b_fil":"Foam extinguisher (Klase A at B)","choice_c_en":"Carbon Dioxide (CO2) or Dry Chemical (Class B and C)","choice_c_fil":"Carbon Dioxide (CO2) o Dry Chemical (Klase B at C)","choice_d_en":"Wet Chemical extinguisher (Class K)","choice_d_fil":"Wet Chemical extinguisher (Klase K)"},{"number":5,"competency":"knowledge","correct_answer":"A","question_en":"The smell of \'burning plastic\' and \'thick, acrid smoke\' are indicators that the fire likely involves what class of combustible materials, besides the electrical component?","question_fil":"Ang amoy ng \'nasusunog na plastik\' at \'makapal, mapanghi na usok\' ay mga indikasyon na ang sunog ay malamang na kinasasangkutan ng anong klase ng nasusunog na materyales, bukod sa electrical component?","explanation_en":"While the source is electrical (Class C), burning plastic, which is an ordinary combustible, indicates involvement of Class A materials. Electrical equipment often contains plastic components which, when burning, produce thick, acrid smoke.","explanation_fil":"Bagaman ang pinagmulan ay electrical (Klase C), ang nasusunog na plastik, na isang karaniwang nasusunog na materyal, ay nagpapahiwatig ng pagkakasangkot ng mga materyal na Klase A. Ang mga electrical na kagamitan ay madalas na naglalaman ng mga plastic na bahagi na, kapag nasusunog, ay gumagawa ng makapal, mapanghi na usok.","choice_a_en":"Class A (Ordinary combustibles like wood, paper)","choice_a_fil":"Klase A (Mga karaniwang nasusunog tulad ng kahoy, papel)","choice_b_en":"Class B (Flammable liquids)","choice_b_fil":"Klase B (Mga madaling masunog na likido)","choice_c_en":"Class D (Combustible metals)","choice_c_fil":"Klase D (Mga nasusunog na metal)","choice_d_en":"Class K (Cooking oils\\/fats)","choice_d_fil":"Klase K (Mga langis\\/taba sa pagluluto)"},{"number":6,"competency":"safety_awareness","correct_answer":"B","question_en":"Why is it crucial for the LGU to ensure that fire extinguishers in public facilities like the Multi-Purpose Hall have clearly obvious types and assigned operators?","question_fil":"Bakit mahalaga para sa LGU na tiyakin na ang mga fire extinguisher sa mga pampublikong pasilidad tulad ng Multi-Purpose Hall ay may malinaw na uri at itinalagang gumagamit?","explanation_en":"Knowing the type ensures the right extinguisher is used for the fire class, and assigned operators ensure someone trained can act quickly and correctly.","explanation_fil":"Ang pag-alam sa uri ay nagsisiguro na ang tamang extinguisher ang gagamitin para sa klase ng sunog, at ang mga itinalagang gumagamit ay nagsisiguro na mayroong sinanay na makakakilos nang mabilis at tama.","choice_a_en":"To comply with aesthetic building standards.","choice_a_fil":"Upang sumunod sa aesthetic building standards.","choice_b_en":"To ensure efficient and correct use during an emergency.","choice_b_fil":"Upang matiyak ang epektibo at tamang paggamit sa panahon ng emerhensiya.","choice_c_en":"To reduce the cost of maintenance.","choice_c_fil":"Upang mabawasan ang gastos sa pagpapanatili.","choice_d_en":"To prevent unauthorized use by children.","choice_d_fil":"Upang maiwasan ang hindi awtorisadong paggamit ng mga bata."},{"number":7,"competency":"decision_making","correct_answer":"C","question_en":"Given the rapid thickening of smoke and potential for panic, what is the most responsible action for Barangay Kagawads and LGU staff present during the evacuation?","question_fil":"Dahil sa mabilis na pagkapal ng usok at posibleng pagkalat ng takot, ano ang pinakaresponsableng aksyon para sa mga Barangay Kagawad at kawani ng LGU na naroroon sa panahon ng paglikas?","explanation_en":"In a rapidly deteriorating situation with smoke and panic, the priority is to get people out safely and quickly, with LGU staff leading and assisting, especially vulnerable individuals.","explanation_fil":"Sa isang mabilis na lumalalang sitwasyon na may usok at takot, ang priyoridad ay mailabas ang mga tao nang ligtas at mabilis, kung saan ang mga kawani ng LGU ang mangunguna at tutulong, lalo na ang mga mahihinang indibidwal.","choice_a_en":"Run out first to avoid the smoke.","choice_a_fil":"Unang tumakbo palabas upang maiwasan ang usok.","choice_b_en":"Instruct residents to form an orderly line before exiting.","choice_b_fil":"Utusan ang mga residente na bumuo ng maayos na linya bago lumabas.","choice_c_en":"Guide residents to the nearest clear exit, prioritizing vulnerable groups.","choice_c_fil":"Gabayan ang mga residente sa pinakamalapit na malinaw na labasan, inuuna ang mga mahihinang grupo.","choice_d_en":"Wait for the fire department to arrive before moving anyone.","choice_d_fil":"Hintayin ang pagdating ng bumbero bago ilipat ang sinuman."},{"number":8,"competency":"emergency_response","correct_answer":"C","question_en":"If the manual fire alarm pull station is located near the stage, close to the developing fire, and accessing it poses an immediate risk, what alternative emergency response action should be prioritized?","question_fil":"Kung ang manual fire alarm pull station ay matatagpuan malapit sa entablado, malapit sa umuusbong na apoy, at ang paglapit dito ay nagdudulot ng agarang panganib, anong alternatibong aksyon sa pagtugon sa emerhensiya ang dapat unahin?","explanation_en":"If the alarm system is inaccessible or dangerous to reach, directly contacting emergency services is critical while simultaneously initiating evacuation and shouting warnings.","explanation_fil":"Kung hindi maabot o mapanganib ang sistema ng alarma, ang direktang pagtawag sa mga serbisyong pang-emerhensiya ay kritikal habang sabay na sinisimulan ang paglikas at pagsigaw ng mga babala.","choice_a_en":"Shout \'Fire!\' repeatedly to alert everyone.","choice_a_fil":"Sumigaw ng \'Sunog!\' nang paulit-ulit upang alertuhin ang lahat.","choice_b_en":"Attempt to put out the fire immediately, regardless of risk.","choice_b_fil":"Subukang patayin agad ang apoy, anuman ang panganib.","choice_c_en":"Directly call 911\\/local emergency services while supervising evacuation.","choice_c_fil":"Direktang tumawag sa 911\\/lokal na serbisyong pang-emerhensiya habang pinangangasiwaan ang paglikas.","choice_d_en":"Wait for the fire to grow larger before acting.","choice_d_fil":"Hintayin munang lumaki ang apoy bago kumilos."},{"number":9,"competency":"knowledge","correct_answer":"A","question_en":"The \'PASS\' technique for operating a fire extinguisher stands for:","question_fil":"Ang teknik na \'PASS\' para sa paggamit ng fire extinguisher ay nangangahulugang:","explanation_en":"This is the standard acronym for operating a fire extinguisher, as covered in fire safety training modules.","explanation_fil":"Ito ang pamantayang acronym para sa paggamit ng fire extinguisher, gaya ng sakop sa mga modyul ng pagsasanay sa kaligtasan sa sunog.","choice_a_en":"Pull, Aim, Squeeze, Sweep","choice_a_fil":"Hilahin (Pull), Itutok (Aim), Pigain (Squeeze), Walisin (Sweep)","choice_b_en":"Press, Activate, Stop, Spray","choice_b_fil":"Pindutin (Press), I-aktibo (Activate), Huminto (Stop), I-spray (Spray)","choice_c_en":"Pump, Alert, Secure, Stand","choice_c_fil":"Pump (Pump), I-alert (Alert), I-secure (Secure), Tumayo (Stand)","choice_d_en":"Point, Advance, Shift, Suppress","choice_d_fil":"Ituro (Point), Umusad (Advance), Lumipat (Shift), Sugpuin (Suppress)"},{"number":10,"competency":"safety_awareness","correct_answer":"C","question_en":"Why is it crucial to regularly inspect and maintain electrical systems, such as air conditioning units and power strips, in public facilities?","question_fil":"Bakit mahalaga ang regular na pag-inspeksyon at pagpapanatili ng mga sistemang elektrikal, tulad ng mga air conditioning unit at power strip, sa mga pampublikong pasilidad?","explanation_en":"Regular maintenance and inspection are key fire prevention practices, especially for electrical systems, to mitigate risks of shorts and fires.","explanation_fil":"Ang regular na pagpapanatili at inspeksyon ay mga pangunahing kasanayan sa pag-iwas sa sunog, lalo na para sa mga sistemang elektrikal, upang mabawasan ang panganib ng mga short circuit at sunog.","choice_a_en":"To keep utility bills low.","choice_a_fil":"Upang panatilihing mababa ang mga bayarin sa utility.","choice_b_en":"To extend the lifespan of the equipment.","choice_b_fil":"Upang pahabain ang buhay ng kagamitan.","choice_c_en":"To prevent electrical overloads and potential fire incidents.","choice_c_fil":"Upang maiwasan ang electrical overloads at posibleng insidente ng sunog.","choice_d_en":"To meet aesthetic standards of the facility.","choice_d_fil":"Upang matugunan ang aesthetic standards ng pasilidad."},{"number":11,"competency":"decision_making","correct_answer":"B","question_en":"During the evacuation, Barangay Kagawad Maria observes a group of seniors struggling near a partially obstructed exit. What is her most appropriate action?","question_fil":"Sa panahon ng paglikas, napansin ni Barangay Kagawad Maria ang isang grupo ng mga nakatatanda na nahihirapan malapit sa isang bahagyang nakaharang na labasan. Ano ang pinakaangkop niyang aksyon?","explanation_en":"LGU personnel should prioritize assisting vulnerable groups and, if safe, remove immediate obstructions to facilitate their exit.","explanation_fil":"Dapat unahin ng mga tauhan ng LGU ang pagtulong sa mga mahihinang grupo at, kung ligtas, alisin ang mga agarang harang upang mapadali ang kanilang paglabas.","choice_a_en":"Tell them to hurry up or they will be left behind.","choice_a_fil":"Sabihin sa kanila na magmadali kung hindi ay maiiwan sila.","choice_b_en":"Clear the obstruction quickly if safe, and actively assist them out.","choice_b_fil":"Alisin kaagad ang harang kung ligtas, at aktibong tulungan silang lumabas.","choice_c_en":"Direct them to an alternative exit which might be further away.","choice_c_fil":"Idirekta sila sa isang alternatibong labasan na maaaring mas malayo.","choice_d_en":"Focus on guiding other able-bodied individuals first.","choice_d_fil":"Magpokus muna sa paggabay sa iba pang may kakayahang indibidwal."},{"number":12,"competency":"emergency_response","correct_answer":"B","question_en":"After the successful evacuation of the hall, what is the next critical step for the LGU personnel to ensure public safety?","question_fil":"Matapos ang matagumpay na paglikas sa bulwagan, ano ang susunod na kritikal na hakbang para sa mga tauhan ng LGU upang matiyak ang kaligtasan ng publiko?","explanation_en":"After evacuation, it is crucial to account for everyone to ensure no one is left behind or trapped, usually at a predetermined assembly point.","explanation_fil":"Matapos ang paglikas, mahalaga ang pagbibilang ng lahat upang matiyak na walang naiwan o na-trap, karaniwan sa isang itinakdang assembly point.","choice_a_en":"Allow everyone to re-enter the building to retrieve belongings.","choice_a_fil":"Pahintulutan ang lahat na muling pumasok sa gusali upang kunin ang mga gamit.","choice_b_en":"Conduct a headcount at a designated safe assembly point.","choice_b_fil":"Magsagawa ng pagbibilang ng tao sa isang itinalagang ligtas na lugar ng pagtitipon.","choice_c_en":"Start an immediate investigation into the cause of the fire.","choice_c_fil":"Simulan ang agarang imbestigasyon sa sanhi ng sunog.","choice_d_en":"Dismiss everyone to go home and wait for official reports.","choice_d_fil":"Paalisin ang lahat upang umuwi at maghintay ng mga opisyal na ulat."},{"number":13,"competency":"knowledge","correct_answer":"A","question_en":"According to basic fire safety principles, what three elements are collectively known as the \'Fire Triangle\' and are necessary for a fire to start and sustain itself?","question_fil":"Ayon sa mga pangunahing prinsipyo ng kaligtasan sa sunog, anong tatlong elemento ang sama-samang kilala bilang \'Fire Triangle\' at kinakailangan para magsimula at manatili ang apoy?","explanation_en":"The Fire Triangle (or Fire Tetrahedron, including Chain Reaction) describes the three essential components for a fire: fuel, oxygen, and heat.","explanation_fil":"Inilalarawan ng Fire Triangle (o Fire Tetrahedron, kasama ang Chain Reaction) ang tatlong mahalagang bahagi para sa isang sunog: gatong, oxygen, at init.","choice_a_en":"Fuel, Oxygen, Heat","choice_a_fil":"Gatong (Fuel), Oxygen, Init (Heat)","choice_b_en":"Smoke, Flames, Ignition","choice_b_fil":"Usok (Smoke), Apoy (Flames), Pag-aapoy (Ignition)","choice_c_en":"Water, Ash, Ember","choice_c_fil":"Tubig (Water), Abo (Ash), Bagas (Ember)","choice_d_en":"Combustibles, Extinguisher, Alarm","choice_d_fil":"Mga Masusunog (Combustibles), Extinguisher, Alarm"},{"number":14,"competency":"decision_making","correct_answer":"B","question_en":"Barangay Captain Reyes notices that a few residents are attempting to re-enter the hall to retrieve personal belongings during the evacuation. What is the most appropriate command to give?","question_fil":"Napansin ni Kapitan Reyes ng Barangay na may ilang residente na sumusubok na muling pumasok sa bulwagan upang kunin ang kanilang mga personal na gamit sa panahon ng paglikas. Ano ang pinakaangkop na utos na ibibigay?","explanation_en":"Re-entering a burning or smoke-filled building is extremely dangerous and must be strictly prohibited to prevent further casualties. Prioritizing life over property is key.","explanation_fil":"Lubhang mapanganib ang muling pagpasok sa isang nasusunog o punong-usok na gusali at dapat mahigpit na ipagbawal upang maiwasan ang karagdagang kaswalti. Mahalaga ang pagbibigay-priyoridad sa buhay kaysa ari-arian.","choice_a_en":"Please get your items quickly and safely!","choice_a_fil":"Pakikuha ang inyong mga gamit nang mabilis at ligtas!","choice_b_en":"Stay out! The building is unsafe, prioritize your lives!","choice_b_fil":"Manatili sa labas! Hindi ligtas ang gusali, unahin ang inyong buhay!","choice_c_en":"Only LGU staff are allowed to re-enter.","choice_c_fil":"Tanging mga kawani lamang ng LGU ang pinapayagan na muling pumasok.","choice_d_en":"Wait for the fire department\'s permission.","choice_d_fil":"Hintayin ang pahintulot ng bumbero."},{"number":15,"competency":"emergency_response","correct_answer":"C","question_en":"If Barangay Captain Reyes decides to attempt initial fire suppression with the available extinguisher, after successfully activating the alarm and initiating evacuation, what is a crucial safety precaution he must ensure before attempting suppression?","question_fil":"Kung magpasya si Kapitan Reyes ng Barangay na subukan ang paunang pagsugpo ng apoy gamit ang magagamit na extinguisher, pagkatapos matagumpay na ma-aktibo ang alarma at masimulan ang paglikas, anong mahalagang pag-iingat sa kaligtasan ang dapat niyang tiyakin bago subukan ang pagsugpo?","explanation_en":"A critical safety rule for initial fire suppression is always to ensure you have a clear and safe exit path if the fire cannot be controlled.","explanation_fil":"Ang isang kritikal na panuntunan sa kaligtasan para sa paunang pagsugpo ng apoy ay palaging tiyakin na mayroon kang malinaw at ligtas na ruta ng paglabas kung hindi makontrol ang apoy.","choice_a_en":"That the fire is completely extinguished before the fire department arrives.","choice_a_fil":"Na ang apoy ay ganap nang naapula bago dumating ang bumbero.","choice_b_en":"That he is alone in the area to avoid distractions.","choice_b_fil":"Na siya ay nag-iisa sa lugar upang maiwasan ang mga abala.","choice_c_en":"That his escape route is clear and unobstructed.","choice_c_fil":"Na ang kanyang ruta ng pagtakas ay malinaw at walang harang.","choice_d_en":"That he has at least two fire extinguishers available.","choice_d_fil":"Na mayroon siyang hindi bababa sa dalawang fire extinguisher na magagamit."},{"number":16,"competency":"knowledge","correct_answer":"D","question_en":"Effective fire prevention practices, as mentioned in the module, generally aim to eliminate or control which component of the fire triangle?","question_fil":"Ang mga epektibong kasanayan sa pag-iwas sa sunog, gaya ng nabanggit sa modyul, ay karaniwang naglalayong alisin o kontrolin ang aling bahagi ng fire triangle?","explanation_en":"Fire prevention aims to remove or control any of the three elements (fuel, oxygen, heat) that can lead to a fire.","explanation_fil":"Ang pag-iwas sa sunog ay naglalayong alisin o kontrolin ang alinman sa tatlong elemento (gatong, oxygen, init) na maaaring magdulot ng sunog.","choice_a_en":"Heat (ignition sources)","choice_a_fil":"Init (mga pinagmulan ng pag-aapoy)","choice_b_en":"Oxygen (air supply)","choice_b_fil":"Oxygen (supply ng hangin)","choice_c_en":"Fuel (combustible materials)","choice_c_fil":"Gatong (mga masusunog na materyales)","choice_d_en":"All of the above","choice_d_fil":"Lahat ng nabanggit"},{"number":17,"competency":"safety_awareness","correct_answer":"A","question_en":"The scenario mentions the fire threatening to spread to nearby curtains. This highlights the importance of:","question_fil":"Binabanggit ng sitwasyon ang banta ng pagkalat ng apoy sa mga kalapit na kurtina. Ito ay nagbibigay-diin sa kahalagahan ng:","explanation_en":"Using fire-retardant materials is a key fire prevention practice, especially for drapes and furnishings, to slow fire spread and prevent rapid escalation.","explanation_fil":"Ang paggamit ng mga fire-retardant na materyales ay isang mahalagang kasanayan sa pag-iwas sa sunog, lalo na para sa mga kurtina at kasangkapan, upang mapabagal ang pagkalat ng apoy at maiwasan ang mabilis na paglala.","choice_a_en":"Using fire-retardant materials in public facilities.","choice_a_fil":"Paggamit ng mga fire-retardant na materyales sa mga pampublikong pasilidad.","choice_b_en":"Keeping curtains clean and dust-free.","choice_b_fil":"Pagpapanatiling malinis at walang alikabok ang mga kurtina.","choice_c_en":"Opening windows to ventilate smoke.","choice_c_fil":"Pagbubukas ng mga bintana upang maipalabas ang usok.","choice_d_en":"Having fire extinguishers specifically for fabrics.","choice_d_fil":"Pagkakaroon ng mga fire extinguisher na partikular para sa mga tela."},{"number":18,"competency":"decision_making","correct_answer":"C","question_en":"After the fire department arrives and takes control of the scene, what is the most appropriate action for the Barangay LGU personnel regarding communicating with the public?","question_fil":"Matapos dumating ang bumbero at kontrolin ang pinangyarihan, ano ang pinakaangkop na aksyon para sa mga tauhan ng Barangay LGU tungkol sa pakikipag-ugnayan sa publiko?","explanation_en":"In a crisis, consistent and accurate communication is vital. A designated spokesperson prevents misinformation and ensures official, factual updates. While directing to the FD for technical details, the LGU still needs to manage its own community communication.","explanation_fil":"Sa isang krisis, mahalaga ang pare-pareho at tumpak na komunikasyon. Pinipigilan ng isang itinalagang tagapagsalita ang maling impormasyon at tinitiyak ang opisyal, faktwal na mga update. Bagaman idinidirekta sa Bumbero para sa mga teknikal na detalye, kailangan pa ring pamahalaan ng LGU ang sarili nitong komunikasyon sa komunidad.","choice_a_en":"Provide immediate, detailed speculation about the fire\'s cause.","choice_a_fil":"Magbigay ng agarang, detalyadong spekulasyon tungkol sa sanhi ng sunog.","choice_b_en":"Direct all media inquiries to the Fire Department Incident Commander.","choice_b_fil":"Idirekta ang lahat ng katanungan ng media sa Fire Department Incident Commander.","choice_c_en":"Assign a single, authorized spokesperson to provide factual updates.","choice_c_fil":"Magtalaga ng isang nag-iisang, awtorisadong tagapagsalita upang magbigay ng mga faktwal na update.","choice_d_en":"Encourage residents to share their personal stories of heroism.","choice_d_fil":"Hikayatin ang mga residente na ibahagi ang kanilang mga personal na kwento ng kabayanihan."},{"number":19,"competency":"emergency_response","correct_answer":"A","question_en":"During the evacuation, if some residents are hesitant to leave due to shock or confusion, LGU personnel should:","question_fil":"Sa panahon ng paglikas, kung ang ilang residente ay nag-aalangan na umalis dahil sa pagkagulat o pagkalito, ang mga tauhan ng LGU ay dapat:","explanation_en":"LGU personnel are expected to lead and assist during emergencies. Gentle but firm guidance is appropriate, while physical force might cause injury or escalate panic. Leaving them behind is unacceptable.","explanation_fil":"Inaasahan ang mga tauhan ng LGU na manguna at tumulong sa panahon ng mga emerhensiya. Ang mahinahon ngunit matatag na paggabay ay angkop, habang ang pisikal na puwersa ay maaaring magdulot ng pinsala o magpalala ng takot. Hindi katanggap-tanggap ang iwanan sila.","choice_a_en":"Gently but firmly guide them towards the exits.","choice_a_fil":"Mahinahon ngunit matatag na gabayan sila patungo sa mga labasan.","choice_b_en":"Physically force them out of the building.","choice_b_fil":"Puwersahang ilabas sila sa gusali.","choice_c_en":"Leave them behind to avoid delaying others.","choice_c_fil":"Iwanan sila upang maiwasan ang pagkaantala ng iba.","choice_d_en":"Wait for them to decide on their own.","choice_d_fil":"Hintayin silang magpasya nang mag-isa."},{"number":20,"competency":"safety_awareness","correct_answer":"B","question_en":"What is a long-term fire safety measure the LGU should implement based on the lessons learned from this incident?","question_fil":"Ano ang isang pangmatagalang hakbang sa kaligtasan sa sunog na dapat ipatupad ng LGU batay sa mga aral na natutunan mula sa insidenteng ito?","explanation_en":"Regular fire drills and reviewing plans are crucial for ensuring preparedness and effective response to future fire incidents, improving safety awareness and emergency response capabilities among both LGU personnel and the community.","explanation_fil":"Ang regular na mga fire drill at pagsusuri ng mga plano ay mahalaga para matiyak ang pagiging handa at epektibong pagtugon sa mga insidente ng sunog sa hinaharap, pagpapabuti ng kamalayan sa kaligtasan at kakayahan sa pagtugon sa emerhensiya sa mga tauhan ng LGU at sa komunidad.","choice_a_en":"Purchase more air conditioning units for comfort.","choice_a_fil":"Bumili ng mas maraming air conditioning unit para sa kaginhawaan.","choice_b_en":"Regularly conduct fire drills and review evacuation plans.","choice_b_fil":"Regular na magsagawa ng mga fire drill at suriin ang mga plano sa paglikas.","choice_c_en":"Increase the number of community assemblies.","choice_c_fil":"Dagdag ang bilang ng mga pagtitipon ng komunidad.","choice_d_en":"Install more decorative curtains in the hall.","choice_d_fil":"Magkabit ng mas maraming pandekorasyong kurtina sa bulwagan."}]', '[]', 0, '2026-06-28 05:06:09', '2026-06-28 05:06:17', '2026-06-28 05:06:17'),
	(2, 34, 5, 2, NULL, NULL, 'Emergency at Barangay Manggahan Multi-Purpose Hall', 'medium', 0, 0, 20, 20, 0.00, 1, 'needs_improvement', 1, 1, 1, 1, 'While your 0% score on the Barangay Manggahan scenario quiz highlights significant opportunities for growth in knowledge, decision-making, emergency response, and safety awareness, it\'s positive that you still passed the module. We encourage you to thoroughly review the core materials for Fire Safety and Emergency Response, focusing particularly on understanding immediate actions and crucial safety protocols. Re-engaging with the foundational content will build your confidence and equip you with the essential skills needed for effective response in future emergencies.', '["Retake AI Scenario Training","Review: Lesson 1: Introduction to Fire Safety","Review: Lesson 3: Fire Prevention"]', '[{"number":10,"competency":"safety_awareness","correct_answer":"B","question_en":"Why is it crucial to regularly inspect and maintain electrical systems, such as air conditioning units and power strips, in public facilities?","question_fil":"Bakit mahalaga ang regular na pag-inspeksyon at pagpapanatili ng mga sistemang elektrikal, tulad ng mga air conditioning unit at power strip, sa mga pampublikong pasilidad?","explanation_en":"Regular maintenance and inspection are key fire prevention practices, especially for electrical systems, to mitigate risks of shorts and fires.","explanation_fil":"Ang regular na pagpapanatili at inspeksyon ay mga pangunahing kasanayan sa pag-iwas sa sunog, lalo na para sa mga sistemang elektrikal, upang mabawasan ang panganib ng mga short circuit at sunog.","choice_a_en":"To keep utility bills low.","choice_a_fil":"Upang panatilihing mababa ang mga bayarin sa utility.","choice_b_en":"To prevent electrical overloads and potential fire incidents.","choice_b_fil":"Upang maiwasan ang electrical overloads at posibleng insidente ng sunog.","choice_c_en":"To extend the lifespan of the equipment.","choice_c_fil":"Upang pahabain ang buhay ng kagamitan.","choice_d_en":"To meet aesthetic standards of the facility.","choice_d_fil":"Upang matugunan ang aesthetic standards ng pasilidad."},{"number":16,"competency":"knowledge","correct_answer":"B","question_en":"Effective fire prevention practices, as mentioned in the module, generally aim to eliminate or control which component of the fire triangle?","question_fil":"Ang mga epektibong kasanayan sa pag-iwas sa sunog, gaya ng nabanggit sa modyul, ay karaniwang naglalayong alisin o kontrolin ang aling bahagi ng fire triangle?","explanation_en":"Fire prevention aims to remove or control any of the three elements (fuel, oxygen, heat) that can lead to a fire.","explanation_fil":"Ang pag-iwas sa sunog ay naglalayong alisin o kontrolin ang alinman sa tatlong elemento (gatong, oxygen, init) na maaaring magdulot ng sunog.","choice_a_en":"Heat (ignition sources)","choice_a_fil":"Init (mga pinagmulan ng pag-aapoy)","choice_b_en":"All of the above","choice_b_fil":"Lahat ng nabanggit","choice_c_en":"Oxygen (air supply)","choice_c_fil":"Oxygen (supply ng hangin)","choice_d_en":"Fuel (combustible materials)","choice_d_fil":"Gatong (mga masusunog na materyales)"},{"number":12,"competency":"emergency_response","correct_answer":"B","question_en":"After the successful evacuation of the hall, what is the next critical step for the LGU personnel to ensure public safety?","question_fil":"Matapos ang matagumpay na paglikas sa bulwagan, ano ang susunod na kritikal na hakbang para sa mga tauhan ng LGU upang matiyak ang kaligtasan ng publiko?","explanation_en":"After evacuation, it is crucial to account for everyone to ensure no one is left behind or trapped, usually at a predetermined assembly point.","explanation_fil":"Matapos ang paglikas, mahalaga ang pagbibilang ng lahat upang matiyak na walang naiwan o na-trap, karaniwan sa isang itinakdang assembly point.","choice_a_en":"Allow everyone to re-enter the building to retrieve belongings.","choice_a_fil":"Pahintulutan ang lahat na muling pumasok sa gusali upang kunin ang mga gamit.","choice_b_en":"Conduct a headcount at a designated safe assembly point.","choice_b_fil":"Magsagawa ng pagbibilang ng tao sa isang itinalagang ligtas na lugar ng pagtitipon.","choice_c_en":"Start an immediate investigation into the cause of the fire.","choice_c_fil":"Simulan ang agarang imbestigasyon sa sanhi ng sunog.","choice_d_en":"Dismiss everyone to go home and wait for official reports.","choice_d_fil":"Paalisin ang lahat upang umuwi at maghintay ng mga opisyal na ulat."},{"number":5,"competency":"knowledge","correct_answer":"A","question_en":"The smell of \'burning plastic\' and \'thick, acrid smoke\' are indicators that the fire likely involves what class of combustible materials, besides the electrical component?","question_fil":"Ang amoy ng \'nasusunog na plastik\' at \'makapal, mapanghi na usok\' ay mga indikasyon na ang sunog ay malamang na kinasasangkutan ng anong klase ng nasusunog na materyales, bukod sa electrical component?","explanation_en":"While the source is electrical (Class C), burning plastic, which is an ordinary combustible, indicates involvement of Class A materials. Electrical equipment often contains plastic components which, when burning, produce thick, acrid smoke.","explanation_fil":"Bagaman ang pinagmulan ay electrical (Klase C), ang nasusunog na plastik, na isang karaniwang nasusunog na materyal, ay nagpapahiwatig ng pagkakasangkot ng mga materyal na Klase A. Ang mga electrical na kagamitan ay madalas na naglalaman ng mga plastic na bahagi na, kapag nasusunog, ay gumagawa ng makapal, mapanghi na usok.","choice_a_en":"Class A (Ordinary combustibles like wood, paper)","choice_a_fil":"Klase A (Mga karaniwang nasusunog tulad ng kahoy, papel)","choice_b_en":"Class K (Cooking oils\\/fats)","choice_b_fil":"Klase K (Mga langis\\/taba sa pagluluto)","choice_c_en":"Class B (Flammable liquids)","choice_c_fil":"Klase B (Mga madaling masunog na likido)","choice_d_en":"Class D (Combustible metals)","choice_d_fil":"Klase D (Mga nasusunog na metal)"},{"number":20,"competency":"safety_awareness","correct_answer":"B","question_en":"What is a long-term fire safety measure the LGU should implement based on the lessons learned from this incident?","question_fil":"Ano ang isang pangmatagalang hakbang sa kaligtasan sa sunog na dapat ipatupad ng LGU batay sa mga aral na natutunan mula sa insidenteng ito?","explanation_en":"Regular fire drills and reviewing plans are crucial for ensuring preparedness and effective response to future fire incidents, improving safety awareness and emergency response capabilities among both LGU personnel and the community.","explanation_fil":"Ang regular na mga fire drill at pagsusuri ng mga plano ay mahalaga para matiyak ang pagiging handa at epektibong pagtugon sa mga insidente ng sunog sa hinaharap, pagpapabuti ng kamalayan sa kaligtasan at kakayahan sa pagtugon sa emerhensiya sa mga tauhan ng LGU at sa komunidad.","choice_a_en":"Purchase more air conditioning units for comfort.","choice_a_fil":"Bumili ng mas maraming air conditioning unit para sa kaginhawaan.","choice_b_en":"Regularly conduct fire drills and review evacuation plans.","choice_b_fil":"Regular na magsagawa ng mga fire drill at suriin ang mga plano sa paglikas.","choice_c_en":"Increase the number of community assemblies.","choice_c_fil":"Dagdag ang bilang ng mga pagtitipon ng komunidad.","choice_d_en":"Install more decorative curtains in the hall.","choice_d_fil":"Magkabit ng mas maraming pandekorasyong kurtina sa bulwagan."},{"number":7,"competency":"decision_making","correct_answer":"B","question_en":"Given the rapid thickening of smoke and potential for panic, what is the most responsible action for Barangay Kagawads and LGU staff present during the evacuation?","question_fil":"Dahil sa mabilis na pagkapal ng usok at posibleng pagkalat ng takot, ano ang pinakaresponsableng aksyon para sa mga Barangay Kagawad at kawani ng LGU na naroroon sa panahon ng paglikas?","explanation_en":"In a rapidly deteriorating situation with smoke and panic, the priority is to get people out safely and quickly, with LGU staff leading and assisting, especially vulnerable individuals.","explanation_fil":"Sa isang mabilis na lumalalang sitwasyon na may usok at takot, ang priyoridad ay mailabas ang mga tao nang ligtas at mabilis, kung saan ang mga kawani ng LGU ang mangunguna at tutulong, lalo na ang mga mahihinang indibidwal.","choice_a_en":"Wait for the fire department to arrive before moving anyone.","choice_a_fil":"Hintayin ang pagdating ng bumbero bago ilipat ang sinuman.","choice_b_en":"Guide residents to the nearest clear exit, prioritizing vulnerable groups.","choice_b_fil":"Gabayan ang mga residente sa pinakamalapit na malinaw na labasan, inuuna ang mga mahihinang grupo.","choice_c_en":"Instruct residents to form an orderly line before exiting.","choice_c_fil":"Utusan ang mga residente na bumuo ng maayos na linya bago lumabas.","choice_d_en":"Run out first to avoid the smoke.","choice_d_fil":"Unang tumakbo palabas upang maiwasan ang usok."},{"number":9,"competency":"knowledge","correct_answer":"D","question_en":"The \'PASS\' technique for operating a fire extinguisher stands for:","question_fil":"Ang teknik na \'PASS\' para sa paggamit ng fire extinguisher ay nangangahulugang:","explanation_en":"This is the standard acronym for operating a fire extinguisher, as covered in fire safety training modules.","explanation_fil":"Ito ang pamantayang acronym para sa paggamit ng fire extinguisher, gaya ng sakop sa mga modyul ng pagsasanay sa kaligtasan sa sunog.","choice_a_en":"Press, Activate, Stop, Spray","choice_a_fil":"Pindutin (Press), I-aktibo (Activate), Huminto (Stop), I-spray (Spray)","choice_b_en":"Point, Advance, Shift, Suppress","choice_b_fil":"Ituro (Point), Umusad (Advance), Lumipat (Shift), Sugpuin (Suppress)","choice_c_en":"Pump, Alert, Secure, Stand","choice_c_fil":"Pump (Pump), I-alert (Alert), I-secure (Secure), Tumayo (Stand)","choice_d_en":"Pull, Aim, Squeeze, Sweep","choice_d_fil":"Hilahin (Pull), Itutok (Aim), Pigain (Squeeze), Walisin (Sweep)"},{"number":14,"competency":"decision_making","correct_answer":"B","question_en":"Barangay Captain Reyes notices that a few residents are attempting to re-enter the hall to retrieve personal belongings during the evacuation. What is the most appropriate command to give?","question_fil":"Napansin ni Kapitan Reyes ng Barangay na may ilang residente na sumusubok na muling pumasok sa bulwagan upang kunin ang kanilang mga personal na gamit sa panahon ng paglikas. Ano ang pinakaangkop na utos na ibibigay?","explanation_en":"Re-entering a burning or smoke-filled building is extremely dangerous and must be strictly prohibited to prevent further casualties. Prioritizing life over property is key.","explanation_fil":"Lubhang mapanganib ang muling pagpasok sa isang nasusunog o punong-usok na gusali at dapat mahigpit na ipagbawal upang maiwasan ang karagdagang kaswalti. Mahalaga ang pagbibigay-priyoridad sa buhay kaysa ari-arian.","choice_a_en":"Wait for the fire department\'s permission.","choice_a_fil":"Hintayin ang pahintulot ng bumbero.","choice_b_en":"Stay out! The building is unsafe, prioritize your lives!","choice_b_fil":"Manatili sa labas! Hindi ligtas ang gusali, unahin ang inyong buhay!","choice_c_en":"Please get your items quickly and safely!","choice_c_fil":"Pakikuha ang inyong mga gamit nang mabilis at ligtas!","choice_d_en":"Only LGU staff are allowed to re-enter.","choice_d_fil":"Tanging mga kawani lamang ng LGU ang pinapayagan na muling pumasok."},{"number":8,"competency":"emergency_response","correct_answer":"B","question_en":"If the manual fire alarm pull station is located near the stage, close to the developing fire, and accessing it poses an immediate risk, what alternative emergency response action should be prioritized?","question_fil":"Kung ang manual fire alarm pull station ay matatagpuan malapit sa entablado, malapit sa umuusbong na apoy, at ang paglapit dito ay nagdudulot ng agarang panganib, anong alternatibong aksyon sa pagtugon sa emerhensiya ang dapat unahin?","explanation_en":"If the alarm system is inaccessible or dangerous to reach, directly contacting emergency services is critical while simultaneously initiating evacuation and shouting warnings.","explanation_fil":"Kung hindi maabot o mapanganib ang sistema ng alarma, ang direktang pagtawag sa mga serbisyong pang-emerhensiya ay kritikal habang sabay na sinisimulan ang paglikas at pagsigaw ng mga babala.","choice_a_en":"Shout \'Fire!\' repeatedly to alert everyone.","choice_a_fil":"Sumigaw ng \'Sunog!\' nang paulit-ulit upang alertuhin ang lahat.","choice_b_en":"Directly call 911\\/local emergency services while supervising evacuation.","choice_b_fil":"Direktang tumawag sa 911\\/lokal na serbisyong pang-emerhensiya habang pinangangasiwaan ang paglikas.","choice_c_en":"Attempt to put out the fire immediately, regardless of risk.","choice_c_fil":"Subukang patayin agad ang apoy, anuman ang panganib.","choice_d_en":"Wait for the fire to grow larger before acting.","choice_d_fil":"Hintayin munang lumaki ang apoy bago kumilos."},{"number":1,"competency":"knowledge","correct_answer":"B","question_en":"What is one of the most common hazards that can cause injuries, loss of life, and damage to property, as introduced in the Fire Safety module?","question_fil":"Ano ang isa sa mga pinakakaraniwang peligro na maaaring magdulot ng mga pinsala, pagkawala ng buhay, at pinsala sa ari-arian, ayon sa ipinakilala sa modyul ng Kaligtasan sa Sunog?","explanation_en":"Lesson 1, \'Introduction to Fire Safety,\' states that fire is one of the most common hazards.","explanation_fil":"Ang Aralin 1, \'Panimula sa Kaligtasan sa Sunog,\' ay nagsasaad na ang sunog ay isa sa mga pinakakaraniwang peligro.","choice_a_en":"Landslides","choice_a_fil":"Mga Pagguho ng Lupa","choice_b_en":"Fires","choice_b_fil":"Mga Sunog","choice_c_en":"Earthquakes","choice_c_fil":"Mga Lindol","choice_d_en":"Typhoons","choice_d_fil":"Mga Bagyo"},{"number":6,"competency":"safety_awareness","correct_answer":"D","question_en":"Why is it crucial for the LGU to ensure that fire extinguishers in public facilities like the Multi-Purpose Hall have clearly obvious types and assigned operators?","question_fil":"Bakit mahalaga para sa LGU na tiyakin na ang mga fire extinguisher sa mga pampublikong pasilidad tulad ng Multi-Purpose Hall ay may malinaw na uri at itinalagang gumagamit?","explanation_en":"Knowing the type ensures the right extinguisher is used for the fire class, and assigned operators ensure someone trained can act quickly and correctly.","explanation_fil":"Ang pag-alam sa uri ay nagsisiguro na ang tamang extinguisher ang gagamitin para sa klase ng sunog, at ang mga itinalagang gumagamit ay nagsisiguro na mayroong sinanay na makakakilos nang mabilis at tama.","choice_a_en":"To reduce the cost of maintenance.","choice_a_fil":"Upang mabawasan ang gastos sa pagpapanatili.","choice_b_en":"To comply with aesthetic building standards.","choice_b_fil":"Upang sumunod sa aesthetic building standards.","choice_c_en":"To prevent unauthorized use by children.","choice_c_fil":"Upang maiwasan ang hindi awtorisadong paggamit ng mga bata.","choice_d_en":"To ensure efficient and correct use during an emergency.","choice_d_fil":"Upang matiyak ang epektibo at tamang paggamit sa panahon ng emerhensiya."},{"number":15,"competency":"emergency_response","correct_answer":"B","question_en":"If Barangay Captain Reyes decides to attempt initial fire suppression with the available extinguisher, after successfully activating the alarm and initiating evacuation, what is a crucial safety precaution he must ensure before attempting suppression?","question_fil":"Kung magpasya si Kapitan Reyes ng Barangay na subukan ang paunang pagsugpo ng apoy gamit ang magagamit na extinguisher, pagkatapos matagumpay na ma-aktibo ang alarma at masimulan ang paglikas, anong mahalagang pag-iingat sa kaligtasan ang dapat niyang tiyakin bago subukan ang pagsugpo?","explanation_en":"A critical safety rule for initial fire suppression is always to ensure you have a clear and safe exit path if the fire cannot be controlled.","explanation_fil":"Ang isang kritikal na panuntunan sa kaligtasan para sa paunang pagsugpo ng apoy ay palaging tiyakin na mayroon kang malinaw at ligtas na ruta ng paglabas kung hindi makontrol ang apoy.","choice_a_en":"That the fire is completely extinguished before the fire department arrives.","choice_a_fil":"Na ang apoy ay ganap nang naapula bago dumating ang bumbero.","choice_b_en":"That his escape route is clear and unobstructed.","choice_b_fil":"Na ang kanyang ruta ng pagtakas ay malinaw at walang harang.","choice_c_en":"That he has at least two fire extinguishers available.","choice_c_fil":"Na mayroon siyang hindi bababa sa dalawang fire extinguisher na magagamit.","choice_d_en":"That he is alone in the area to avoid distractions.","choice_d_fil":"Na siya ay nag-iisa sa lugar upang maiwasan ang mga abala."},{"number":4,"competency":"emergency_response","correct_answer":"B","question_en":"Considering the fire originated from an electrical source (air conditioning unit), which type of fire extinguisher would be most appropriate to attempt initial suppression, if it were deemed safe to do so?","question_fil":"Isinasaalang-alang na ang sunog ay nagmula sa isang electrical na pinagmulan (air conditioning unit), anong uri ng fire extinguisher ang pinakaangkop na gamitin para sa paunang pagsugpo, kung ito ay itinuring na ligtas gawin?","explanation_en":"Electrical fires are Class C fires. Water and foam are conductive and dangerous for electrical fires. CO2 or dry chemical extinguishers are suitable for Class C fires.","explanation_fil":"Ang mga sunog na electrical ay Klase C. Ang tubig at foam ay conductive at mapanganib para sa mga electrical na sunog. Ang CO2 o dry chemical extinguishers ay angkop para sa mga sunog na Klase C.","choice_a_en":"Water extinguisher (Class A)","choice_a_fil":"Water extinguisher (Klase A)","choice_b_en":"Carbon Dioxide (CO2) or Dry Chemical (Class B and C)","choice_b_fil":"Carbon Dioxide (CO2) o Dry Chemical (Klase B at C)","choice_c_en":"Wet Chemical extinguisher (Class K)","choice_c_fil":"Wet Chemical extinguisher (Klase K)","choice_d_en":"Foam extinguisher (Class A and B)","choice_d_fil":"Foam extinguisher (Klase A at B)"},{"number":3,"competency":"decision_making","correct_answer":"D","question_en":"Upon witnessing the electrical spark and initial flame, what should be Barangay Captain Reyes\' immediate priority action?","question_fil":"Sa pagkakita ng kuryenteng kislap at paunang apoy, ano ang dapat na agarang pangunahing aksyon ni Kapitan Reyes ng Barangay?","explanation_en":"The primary immediate action in a developing fire, especially with an audience, is to alert others and begin evacuation. Initial suppression should only be attempted if safe and trained.","explanation_fil":"Ang pangunahing agarang aksyon sa isang umuusbong na sunog, lalo na kung may mga tao, ay alertuhin ang iba at simulan ang paglikas. Ang paunang pagsugpo ay dapat lamang subukan kung ligtas at may sapat na pagsasanay.","choice_a_en":"Attempt to put out the fire with a bucket of water.","choice_a_fil":"Subukang patayin ang apoy gamit ang isang timba ng tubig.","choice_b_en":"Direct attendees to remain seated calmly.","choice_b_fil":"Utusan ang mga dumalo na manatiling nakaupo nang mahinahon.","choice_c_en":"Call his family to inform them of the situation.","choice_c_fil":"Tumawag sa kanyang pamilya upang ipaalam ang sitwasyon.","choice_d_en":"Initiate the fire alarm and announce evacuation.","choice_d_fil":"Pindutin ang fire alarm at ipahayag ang paglikas."},{"number":13,"competency":"knowledge","correct_answer":"D","question_en":"According to basic fire safety principles, what three elements are collectively known as the \'Fire Triangle\' and are necessary for a fire to start and sustain itself?","question_fil":"Ayon sa mga pangunahing prinsipyo ng kaligtasan sa sunog, anong tatlong elemento ang sama-samang kilala bilang \'Fire Triangle\' at kinakailangan para magsimula at manatili ang apoy?","explanation_en":"The Fire Triangle (or Fire Tetrahedron, including Chain Reaction) describes the three essential components for a fire: fuel, oxygen, and heat.","explanation_fil":"Inilalarawan ng Fire Triangle (o Fire Tetrahedron, kasama ang Chain Reaction) ang tatlong mahalagang bahagi para sa isang sunog: gatong, oxygen, at init.","choice_a_en":"Smoke, Flames, Ignition","choice_a_fil":"Usok (Smoke), Apoy (Flames), Pag-aapoy (Ignition)","choice_b_en":"Water, Ash, Ember","choice_b_fil":"Tubig (Water), Abo (Ash), Bagas (Ember)","choice_c_en":"Combustibles, Extinguisher, Alarm","choice_c_fil":"Mga Masusunog (Combustibles), Extinguisher, Alarm","choice_d_en":"Fuel, Oxygen, Heat","choice_d_fil":"Gatong (Fuel), Oxygen, Init (Heat)"},{"number":19,"competency":"emergency_response","correct_answer":"D","question_en":"During the evacuation, if some residents are hesitant to leave due to shock or confusion, LGU personnel should:","question_fil":"Sa panahon ng paglikas, kung ang ilang residente ay nag-aalangan na umalis dahil sa pagkagulat o pagkalito, ang mga tauhan ng LGU ay dapat:","explanation_en":"LGU personnel are expected to lead and assist during emergencies. Gentle but firm guidance is appropriate, while physical force might cause injury or escalate panic. Leaving them behind is unacceptable.","explanation_fil":"Inaasahan ang mga tauhan ng LGU na manguna at tumulong sa panahon ng mga emerhensiya. Ang mahinahon ngunit matatag na paggabay ay angkop, habang ang pisikal na puwersa ay maaaring magdulot ng pinsala o magpalala ng takot. Hindi katanggap-tanggap ang iwanan sila.","choice_a_en":"Wait for them to decide on their own.","choice_a_fil":"Hintayin silang magpasya nang mag-isa.","choice_b_en":"Physically force them out of the building.","choice_b_fil":"Puwersahang ilabas sila sa gusali.","choice_c_en":"Leave them behind to avoid delaying others.","choice_c_fil":"Iwanan sila upang maiwasan ang pagkaantala ng iba.","choice_d_en":"Gently but firmly guide them towards the exits.","choice_d_fil":"Mahinahon ngunit matatag na gabayan sila patungo sa mga labasan."},{"number":2,"competency":"safety_awareness","correct_answer":"B","question_en":"In the scenario, the presence of old chairs and tables partially obstructing the hall\'s exits primarily poses a risk by:","question_fil":"Sa sitwasyon, ang pagkakaroon ng mga lumang upuan at mesa na bahagyang nakaharang sa mga labasan ng bulwagan ay pangunahing nagdudulot ng panganib sa pamamagitan ng:","explanation_en":"Obstructions near exits directly impede the flow of people during an emergency evacuation, increasing danger and slowing response.","explanation_fil":"Ang mga harang malapit sa mga labasan ay direktang humahadlang sa pagdaloy ng mga tao sa panahon ng emerhensiyang paglikas, na nagpapataas ng panganib at nagpapabagal sa pagtugon.","choice_a_en":"Attracting pests and insects.","choice_a_fil":"Pag-akit ng mga peste at insekto.","choice_b_en":"Hindering efficient evacuation.","choice_b_fil":"Paghadlang sa epektibong paglikas.","choice_c_en":"Causing electrical overloads.","choice_c_fil":"Pagdulot ng electrical overloads.","choice_d_en":"Making the hall look untidy.","choice_d_fil":"Pagpapamukha sa bulwagan na hindi maayos."},{"number":17,"competency":"safety_awareness","correct_answer":"C","question_en":"The scenario mentions the fire threatening to spread to nearby curtains. This highlights the importance of:","question_fil":"Binabanggit ng sitwasyon ang banta ng pagkalat ng apoy sa mga kalapit na kurtina. Ito ay nagbibigay-diin sa kahalagahan ng:","explanation_en":"Using fire-retardant materials is a key fire prevention practice, especially for drapes and furnishings, to slow fire spread and prevent rapid escalation.","explanation_fil":"Ang paggamit ng mga fire-retardant na materyales ay isang mahalagang kasanayan sa pag-iwas sa sunog, lalo na para sa mga kurtina at kasangkapan, upang mapabagal ang pagkalat ng apoy at maiwasan ang mabilis na paglala.","choice_a_en":"Having fire extinguishers specifically for fabrics.","choice_a_fil":"Pagkakaroon ng mga fire extinguisher na partikular para sa mga tela.","choice_b_en":"Keeping curtains clean and dust-free.","choice_b_fil":"Pagpapanatiling malinis at walang alikabok ang mga kurtina.","choice_c_en":"Using fire-retardant materials in public facilities.","choice_c_fil":"Paggamit ng mga fire-retardant na materyales sa mga pampublikong pasilidad.","choice_d_en":"Opening windows to ventilate smoke.","choice_d_fil":"Pagbubukas ng mga bintana upang maipalabas ang usok."},{"number":18,"competency":"decision_making","correct_answer":"B","question_en":"After the fire department arrives and takes control of the scene, what is the most appropriate action for the Barangay LGU personnel regarding communicating with the public?","question_fil":"Matapos dumating ang bumbero at kontrolin ang pinangyarihan, ano ang pinakaangkop na aksyon para sa mga tauhan ng Barangay LGU tungkol sa pakikipag-ugnayan sa publiko?","explanation_en":"In a crisis, consistent and accurate communication is vital. A designated spokesperson prevents misinformation and ensures official, factual updates. While directing to the FD for technical details, the LGU still needs to manage its own community communication.","explanation_fil":"Sa isang krisis, mahalaga ang pare-pareho at tumpak na komunikasyon. Pinipigilan ng isang itinalagang tagapagsalita ang maling impormasyon at tinitiyak ang opisyal, faktwal na mga update. Bagaman idinidirekta sa Bumbero para sa mga teknikal na detalye, kailangan pa ring pamahalaan ng LGU ang sarili nitong komunikasyon sa komunidad.","choice_a_en":"Provide immediate, detailed speculation about the fire\'s cause.","choice_a_fil":"Magbigay ng agarang, detalyadong spekulasyon tungkol sa sanhi ng sunog.","choice_b_en":"Assign a single, authorized spokesperson to provide factual updates.","choice_b_fil":"Magtalaga ng isang nag-iisang, awtorisadong tagapagsalita upang magbigay ng mga faktwal na update.","choice_c_en":"Encourage residents to share their personal stories of heroism.","choice_c_fil":"Hikayatin ang mga residente na ibahagi ang kanilang mga personal na kwento ng kabayanihan.","choice_d_en":"Direct all media inquiries to the Fire Department Incident Commander.","choice_d_fil":"Idirekta ang lahat ng katanungan ng media sa Fire Department Incident Commander."},{"number":11,"competency":"decision_making","correct_answer":"B","question_en":"During the evacuation, Barangay Kagawad Maria observes a group of seniors struggling near a partially obstructed exit. What is her most appropriate action?","question_fil":"Sa panahon ng paglikas, napansin ni Barangay Kagawad Maria ang isang grupo ng mga nakatatanda na nahihirapan malapit sa isang bahagyang nakaharang na labasan. Ano ang pinakaangkop niyang aksyon?","explanation_en":"LGU personnel should prioritize assisting vulnerable groups and, if safe, remove immediate obstructions to facilitate their exit.","explanation_fil":"Dapat unahin ng mga tauhan ng LGU ang pagtulong sa mga mahihinang grupo at, kung ligtas, alisin ang mga agarang harang upang mapadali ang kanilang paglabas.","choice_a_en":"Focus on guiding other able-bodied individuals first.","choice_a_fil":"Magpokus muna sa paggabay sa iba pang may kakayahang indibidwal.","choice_b_en":"Clear the obstruction quickly if safe, and actively assist them out.","choice_b_fil":"Alisin kaagad ang harang kung ligtas, at aktibong tulungan silang lumabas.","choice_c_en":"Tell them to hurry up or they will be left behind.","choice_c_fil":"Sabihin sa kanila na magmadali kung hindi ay maiiwan sila.","choice_d_en":"Direct them to an alternative exit which might be further away.","choice_d_fil":"Idirekta sila sa isang alternatibong labasan na maaaring mas malayo."}]', '[]', 0, '2026-06-28 05:19:47', '2026-06-28 05:19:52', '2026-06-28 05:19:52'),
	(3, 34, 5, 3, NULL, NULL, 'Emergency at Barangay Manggahan Multi-Purpose Hall', 'medium', 0, 0, 20, 20, 0.00, 1, 'needs_improvement', 1, 1, 1, 1, 'Your recent performance in the \'Emergency at Barangay Manggahan Multi-Purpose Hall\' AI scenario quiz, while indicating a need for deeper engagement, effectively highlights key areas for your continued development in fire safety knowledge, effective decision-making, and overall emergency response. We encourage you to revisit the \'Fire Safety and Emergency Response\' module with a focus on foundational principles and practical steps to significantly enhance your safety awareness and preparedness for future incidents.', '["Retake AI Scenario Training","Review: Lesson 1: Introduction to Fire Safety","Review: Lesson 3: Fire Prevention"]', '[{"number":19,"competency":"emergency_response","correct_answer":"C","question_en":"During the evacuation, if some residents are hesitant to leave due to shock or confusion, LGU personnel should:","question_fil":"Sa panahon ng paglikas, kung ang ilang residente ay nag-aalangan na umalis dahil sa pagkagulat o pagkalito, ang mga tauhan ng LGU ay dapat:","explanation_en":"LGU personnel are expected to lead and assist during emergencies. Gentle but firm guidance is appropriate, while physical force might cause injury or escalate panic. Leaving them behind is unacceptable.","explanation_fil":"Inaasahan ang mga tauhan ng LGU na manguna at tumulong sa panahon ng mga emerhensiya. Ang mahinahon ngunit matatag na paggabay ay angkop, habang ang pisikal na puwersa ay maaaring magdulot ng pinsala o magpalala ng takot. Hindi katanggap-tanggap ang iwanan sila.","choice_a_en":"Physically force them out of the building.","choice_a_fil":"Puwersahang ilabas sila sa gusali.","choice_b_en":"Wait for them to decide on their own.","choice_b_fil":"Hintayin silang magpasya nang mag-isa.","choice_c_en":"Gently but firmly guide them towards the exits.","choice_c_fil":"Mahinahon ngunit matatag na gabayan sila patungo sa mga labasan.","choice_d_en":"Leave them behind to avoid delaying others.","choice_d_fil":"Iwanan sila upang maiwasan ang pagkaantala ng iba."},{"number":3,"competency":"decision_making","correct_answer":"C","question_en":"Upon witnessing the electrical spark and initial flame, what should be Barangay Captain Reyes\' immediate priority action?","question_fil":"Sa pagkakita ng kuryenteng kislap at paunang apoy, ano ang dapat na agarang pangunahing aksyon ni Kapitan Reyes ng Barangay?","explanation_en":"The primary immediate action in a developing fire, especially with an audience, is to alert others and begin evacuation. Initial suppression should only be attempted if safe and trained.","explanation_fil":"Ang pangunahing agarang aksyon sa isang umuusbong na sunog, lalo na kung may mga tao, ay alertuhin ang iba at simulan ang paglikas. Ang paunang pagsugpo ay dapat lamang subukan kung ligtas at may sapat na pagsasanay.","choice_a_en":"Attempt to put out the fire with a bucket of water.","choice_a_fil":"Subukang patayin ang apoy gamit ang isang timba ng tubig.","choice_b_en":"Direct attendees to remain seated calmly.","choice_b_fil":"Utusan ang mga dumalo na manatiling nakaupo nang mahinahon.","choice_c_en":"Initiate the fire alarm and announce evacuation.","choice_c_fil":"Pindutin ang fire alarm at ipahayag ang paglikas.","choice_d_en":"Call his family to inform them of the situation.","choice_d_fil":"Tumawag sa kanyang pamilya upang ipaalam ang sitwasyon."},{"number":8,"competency":"emergency_response","correct_answer":"B","question_en":"If the manual fire alarm pull station is located near the stage, close to the developing fire, and accessing it poses an immediate risk, what alternative emergency response action should be prioritized?","question_fil":"Kung ang manual fire alarm pull station ay matatagpuan malapit sa entablado, malapit sa umuusbong na apoy, at ang paglapit dito ay nagdudulot ng agarang panganib, anong alternatibong aksyon sa pagtugon sa emerhensiya ang dapat unahin?","explanation_en":"If the alarm system is inaccessible or dangerous to reach, directly contacting emergency services is critical while simultaneously initiating evacuation and shouting warnings.","explanation_fil":"Kung hindi maabot o mapanganib ang sistema ng alarma, ang direktang pagtawag sa mga serbisyong pang-emerhensiya ay kritikal habang sabay na sinisimulan ang paglikas at pagsigaw ng mga babala.","choice_a_en":"Wait for the fire to grow larger before acting.","choice_a_fil":"Hintayin munang lumaki ang apoy bago kumilos.","choice_b_en":"Directly call 911\\/local emergency services while supervising evacuation.","choice_b_fil":"Direktang tumawag sa 911\\/lokal na serbisyong pang-emerhensiya habang pinangangasiwaan ang paglikas.","choice_c_en":"Shout \'Fire!\' repeatedly to alert everyone.","choice_c_fil":"Sumigaw ng \'Sunog!\' nang paulit-ulit upang alertuhin ang lahat.","choice_d_en":"Attempt to put out the fire immediately, regardless of risk.","choice_d_fil":"Subukang patayin agad ang apoy, anuman ang panganib."},{"number":17,"competency":"safety_awareness","correct_answer":"A","question_en":"The scenario mentions the fire threatening to spread to nearby curtains. This highlights the importance of:","question_fil":"Binabanggit ng sitwasyon ang banta ng pagkalat ng apoy sa mga kalapit na kurtina. Ito ay nagbibigay-diin sa kahalagahan ng:","explanation_en":"Using fire-retardant materials is a key fire prevention practice, especially for drapes and furnishings, to slow fire spread and prevent rapid escalation.","explanation_fil":"Ang paggamit ng mga fire-retardant na materyales ay isang mahalagang kasanayan sa pag-iwas sa sunog, lalo na para sa mga kurtina at kasangkapan, upang mapabagal ang pagkalat ng apoy at maiwasan ang mabilis na paglala.","choice_a_en":"Using fire-retardant materials in public facilities.","choice_a_fil":"Paggamit ng mga fire-retardant na materyales sa mga pampublikong pasilidad.","choice_b_en":"Having fire extinguishers specifically for fabrics.","choice_b_fil":"Pagkakaroon ng mga fire extinguisher na partikular para sa mga tela.","choice_c_en":"Opening windows to ventilate smoke.","choice_c_fil":"Pagbubukas ng mga bintana upang maipalabas ang usok.","choice_d_en":"Keeping curtains clean and dust-free.","choice_d_fil":"Pagpapanatiling malinis at walang alikabok ang mga kurtina."},{"number":13,"competency":"knowledge","correct_answer":"C","question_en":"According to basic fire safety principles, what three elements are collectively known as the \'Fire Triangle\' and are necessary for a fire to start and sustain itself?","question_fil":"Ayon sa mga pangunahing prinsipyo ng kaligtasan sa sunog, anong tatlong elemento ang sama-samang kilala bilang \'Fire Triangle\' at kinakailangan para magsimula at manatili ang apoy?","explanation_en":"The Fire Triangle (or Fire Tetrahedron, including Chain Reaction) describes the three essential components for a fire: fuel, oxygen, and heat.","explanation_fil":"Inilalarawan ng Fire Triangle (o Fire Tetrahedron, kasama ang Chain Reaction) ang tatlong mahalagang bahagi para sa isang sunog: gatong, oxygen, at init.","choice_a_en":"Water, Ash, Ember","choice_a_fil":"Tubig (Water), Abo (Ash), Bagas (Ember)","choice_b_en":"Smoke, Flames, Ignition","choice_b_fil":"Usok (Smoke), Apoy (Flames), Pag-aapoy (Ignition)","choice_c_en":"Fuel, Oxygen, Heat","choice_c_fil":"Gatong (Fuel), Oxygen, Init (Heat)","choice_d_en":"Combustibles, Extinguisher, Alarm","choice_d_fil":"Mga Masusunog (Combustibles), Extinguisher, Alarm"},{"number":16,"competency":"knowledge","correct_answer":"B","question_en":"Effective fire prevention practices, as mentioned in the module, generally aim to eliminate or control which component of the fire triangle?","question_fil":"Ang mga epektibong kasanayan sa pag-iwas sa sunog, gaya ng nabanggit sa modyul, ay karaniwang naglalayong alisin o kontrolin ang aling bahagi ng fire triangle?","explanation_en":"Fire prevention aims to remove or control any of the three elements (fuel, oxygen, heat) that can lead to a fire.","explanation_fil":"Ang pag-iwas sa sunog ay naglalayong alisin o kontrolin ang alinman sa tatlong elemento (gatong, oxygen, init) na maaaring magdulot ng sunog.","choice_a_en":"Heat (ignition sources)","choice_a_fil":"Init (mga pinagmulan ng pag-aapoy)","choice_b_en":"All of the above","choice_b_fil":"Lahat ng nabanggit","choice_c_en":"Fuel (combustible materials)","choice_c_fil":"Gatong (mga masusunog na materyales)","choice_d_en":"Oxygen (air supply)","choice_d_fil":"Oxygen (supply ng hangin)"},{"number":15,"competency":"emergency_response","correct_answer":"C","question_en":"If Barangay Captain Reyes decides to attempt initial fire suppression with the available extinguisher, after successfully activating the alarm and initiating evacuation, what is a crucial safety precaution he must ensure before attempting suppression?","question_fil":"Kung magpasya si Kapitan Reyes ng Barangay na subukan ang paunang pagsugpo ng apoy gamit ang magagamit na extinguisher, pagkatapos matagumpay na ma-aktibo ang alarma at masimulan ang paglikas, anong mahalagang pag-iingat sa kaligtasan ang dapat niyang tiyakin bago subukan ang pagsugpo?","explanation_en":"A critical safety rule for initial fire suppression is always to ensure you have a clear and safe exit path if the fire cannot be controlled.","explanation_fil":"Ang isang kritikal na panuntunan sa kaligtasan para sa paunang pagsugpo ng apoy ay palaging tiyakin na mayroon kang malinaw at ligtas na ruta ng paglabas kung hindi makontrol ang apoy.","choice_a_en":"That he is alone in the area to avoid distractions.","choice_a_fil":"Na siya ay nag-iisa sa lugar upang maiwasan ang mga abala.","choice_b_en":"That he has at least two fire extinguishers available.","choice_b_fil":"Na mayroon siyang hindi bababa sa dalawang fire extinguisher na magagamit.","choice_c_en":"That his escape route is clear and unobstructed.","choice_c_fil":"Na ang kanyang ruta ng pagtakas ay malinaw at walang harang.","choice_d_en":"That the fire is completely extinguished before the fire department arrives.","choice_d_fil":"Na ang apoy ay ganap nang naapula bago dumating ang bumbero."},{"number":14,"competency":"decision_making","correct_answer":"B","question_en":"Barangay Captain Reyes notices that a few residents are attempting to re-enter the hall to retrieve personal belongings during the evacuation. What is the most appropriate command to give?","question_fil":"Napansin ni Kapitan Reyes ng Barangay na may ilang residente na sumusubok na muling pumasok sa bulwagan upang kunin ang kanilang mga personal na gamit sa panahon ng paglikas. Ano ang pinakaangkop na utos na ibibigay?","explanation_en":"Re-entering a burning or smoke-filled building is extremely dangerous and must be strictly prohibited to prevent further casualties. Prioritizing life over property is key.","explanation_fil":"Lubhang mapanganib ang muling pagpasok sa isang nasusunog o punong-usok na gusali at dapat mahigpit na ipagbawal upang maiwasan ang karagdagang kaswalti. Mahalaga ang pagbibigay-priyoridad sa buhay kaysa ari-arian.","choice_a_en":"Please get your items quickly and safely!","choice_a_fil":"Pakikuha ang inyong mga gamit nang mabilis at ligtas!","choice_b_en":"Stay out! The building is unsafe, prioritize your lives!","choice_b_fil":"Manatili sa labas! Hindi ligtas ang gusali, unahin ang inyong buhay!","choice_c_en":"Only LGU staff are allowed to re-enter.","choice_c_fil":"Tanging mga kawani lamang ng LGU ang pinapayagan na muling pumasok.","choice_d_en":"Wait for the fire department\'s permission.","choice_d_fil":"Hintayin ang pahintulot ng bumbero."},{"number":5,"competency":"knowledge","correct_answer":"A","question_en":"The smell of \'burning plastic\' and \'thick, acrid smoke\' are indicators that the fire likely involves what class of combustible materials, besides the electrical component?","question_fil":"Ang amoy ng \'nasusunog na plastik\' at \'makapal, mapanghi na usok\' ay mga indikasyon na ang sunog ay malamang na kinasasangkutan ng anong klase ng nasusunog na materyales, bukod sa electrical component?","explanation_en":"While the source is electrical (Class C), burning plastic, which is an ordinary combustible, indicates involvement of Class A materials. Electrical equipment often contains plastic components which, when burning, produce thick, acrid smoke.","explanation_fil":"Bagaman ang pinagmulan ay electrical (Klase C), ang nasusunog na plastik, na isang karaniwang nasusunog na materyal, ay nagpapahiwatig ng pagkakasangkot ng mga materyal na Klase A. Ang mga electrical na kagamitan ay madalas na naglalaman ng mga plastic na bahagi na, kapag nasusunog, ay gumagawa ng makapal, mapanghi na usok.","choice_a_en":"Class A (Ordinary combustibles like wood, paper)","choice_a_fil":"Klase A (Mga karaniwang nasusunog tulad ng kahoy, papel)","choice_b_en":"Class D (Combustible metals)","choice_b_fil":"Klase D (Mga nasusunog na metal)","choice_c_en":"Class K (Cooking oils\\/fats)","choice_c_fil":"Klase K (Mga langis\\/taba sa pagluluto)","choice_d_en":"Class B (Flammable liquids)","choice_d_fil":"Klase B (Mga madaling masunog na likido)"},{"number":20,"competency":"safety_awareness","correct_answer":"D","question_en":"What is a long-term fire safety measure the LGU should implement based on the lessons learned from this incident?","question_fil":"Ano ang isang pangmatagalang hakbang sa kaligtasan sa sunog na dapat ipatupad ng LGU batay sa mga aral na natutunan mula sa insidenteng ito?","explanation_en":"Regular fire drills and reviewing plans are crucial for ensuring preparedness and effective response to future fire incidents, improving safety awareness and emergency response capabilities among both LGU personnel and the community.","explanation_fil":"Ang regular na mga fire drill at pagsusuri ng mga plano ay mahalaga para matiyak ang pagiging handa at epektibong pagtugon sa mga insidente ng sunog sa hinaharap, pagpapabuti ng kamalayan sa kaligtasan at kakayahan sa pagtugon sa emerhensiya sa mga tauhan ng LGU at sa komunidad.","choice_a_en":"Install more decorative curtains in the hall.","choice_a_fil":"Magkabit ng mas maraming pandekorasyong kurtina sa bulwagan.","choice_b_en":"Purchase more air conditioning units for comfort.","choice_b_fil":"Bumili ng mas maraming air conditioning unit para sa kaginhawaan.","choice_c_en":"Increase the number of community assemblies.","choice_c_fil":"Dagdag ang bilang ng mga pagtitipon ng komunidad.","choice_d_en":"Regularly conduct fire drills and review evacuation plans.","choice_d_fil":"Regular na magsagawa ng mga fire drill at suriin ang mga plano sa paglikas."},{"number":6,"competency":"safety_awareness","correct_answer":"B","question_en":"Why is it crucial for the LGU to ensure that fire extinguishers in public facilities like the Multi-Purpose Hall have clearly obvious types and assigned operators?","question_fil":"Bakit mahalaga para sa LGU na tiyakin na ang mga fire extinguisher sa mga pampublikong pasilidad tulad ng Multi-Purpose Hall ay may malinaw na uri at itinalagang gumagamit?","explanation_en":"Knowing the type ensures the right extinguisher is used for the fire class, and assigned operators ensure someone trained can act quickly and correctly.","explanation_fil":"Ang pag-alam sa uri ay nagsisiguro na ang tamang extinguisher ang gagamitin para sa klase ng sunog, at ang mga itinalagang gumagamit ay nagsisiguro na mayroong sinanay na makakakilos nang mabilis at tama.","choice_a_en":"To comply with aesthetic building standards.","choice_a_fil":"Upang sumunod sa aesthetic building standards.","choice_b_en":"To ensure efficient and correct use during an emergency.","choice_b_fil":"Upang matiyak ang epektibo at tamang paggamit sa panahon ng emerhensiya.","choice_c_en":"To reduce the cost of maintenance.","choice_c_fil":"Upang mabawasan ang gastos sa pagpapanatili.","choice_d_en":"To prevent unauthorized use by children.","choice_d_fil":"Upang maiwasan ang hindi awtorisadong paggamit ng mga bata."},{"number":7,"competency":"decision_making","correct_answer":"B","question_en":"Given the rapid thickening of smoke and potential for panic, what is the most responsible action for Barangay Kagawads and LGU staff present during the evacuation?","question_fil":"Dahil sa mabilis na pagkapal ng usok at posibleng pagkalat ng takot, ano ang pinakaresponsableng aksyon para sa mga Barangay Kagawad at kawani ng LGU na naroroon sa panahon ng paglikas?","explanation_en":"In a rapidly deteriorating situation with smoke and panic, the priority is to get people out safely and quickly, with LGU staff leading and assisting, especially vulnerable individuals.","explanation_fil":"Sa isang mabilis na lumalalang sitwasyon na may usok at takot, ang priyoridad ay mailabas ang mga tao nang ligtas at mabilis, kung saan ang mga kawani ng LGU ang mangunguna at tutulong, lalo na ang mga mahihinang indibidwal.","choice_a_en":"Wait for the fire department to arrive before moving anyone.","choice_a_fil":"Hintayin ang pagdating ng bumbero bago ilipat ang sinuman.","choice_b_en":"Guide residents to the nearest clear exit, prioritizing vulnerable groups.","choice_b_fil":"Gabayan ang mga residente sa pinakamalapit na malinaw na labasan, inuuna ang mga mahihinang grupo.","choice_c_en":"Run out first to avoid the smoke.","choice_c_fil":"Unang tumakbo palabas upang maiwasan ang usok.","choice_d_en":"Instruct residents to form an orderly line before exiting.","choice_d_fil":"Utusan ang mga residente na bumuo ng maayos na linya bago lumabas."},{"number":18,"competency":"decision_making","correct_answer":"D","question_en":"After the fire department arrives and takes control of the scene, what is the most appropriate action for the Barangay LGU personnel regarding communicating with the public?","question_fil":"Matapos dumating ang bumbero at kontrolin ang pinangyarihan, ano ang pinakaangkop na aksyon para sa mga tauhan ng Barangay LGU tungkol sa pakikipag-ugnayan sa publiko?","explanation_en":"In a crisis, consistent and accurate communication is vital. A designated spokesperson prevents misinformation and ensures official, factual updates. While directing to the FD for technical details, the LGU still needs to manage its own community communication.","explanation_fil":"Sa isang krisis, mahalaga ang pare-pareho at tumpak na komunikasyon. Pinipigilan ng isang itinalagang tagapagsalita ang maling impormasyon at tinitiyak ang opisyal, faktwal na mga update. Bagaman idinidirekta sa Bumbero para sa mga teknikal na detalye, kailangan pa ring pamahalaan ng LGU ang sarili nitong komunikasyon sa komunidad.","choice_a_en":"Encourage residents to share their personal stories of heroism.","choice_a_fil":"Hikayatin ang mga residente na ibahagi ang kanilang mga personal na kwento ng kabayanihan.","choice_b_en":"Provide immediate, detailed speculation about the fire\'s cause.","choice_b_fil":"Magbigay ng agarang, detalyadong spekulasyon tungkol sa sanhi ng sunog.","choice_c_en":"Direct all media inquiries to the Fire Department Incident Commander.","choice_c_fil":"Idirekta ang lahat ng katanungan ng media sa Fire Department Incident Commander.","choice_d_en":"Assign a single, authorized spokesperson to provide factual updates.","choice_d_fil":"Magtalaga ng isang nag-iisang, awtorisadong tagapagsalita upang magbigay ng mga faktwal na update."},{"number":12,"competency":"emergency_response","correct_answer":"A","question_en":"After the successful evacuation of the hall, what is the next critical step for the LGU personnel to ensure public safety?","question_fil":"Matapos ang matagumpay na paglikas sa bulwagan, ano ang susunod na kritikal na hakbang para sa mga tauhan ng LGU upang matiyak ang kaligtasan ng publiko?","explanation_en":"After evacuation, it is crucial to account for everyone to ensure no one is left behind or trapped, usually at a predetermined assembly point.","explanation_fil":"Matapos ang paglikas, mahalaga ang pagbibilang ng lahat upang matiyak na walang naiwan o na-trap, karaniwan sa isang itinakdang assembly point.","choice_a_en":"Conduct a headcount at a designated safe assembly point.","choice_a_fil":"Magsagawa ng pagbibilang ng tao sa isang itinalagang ligtas na lugar ng pagtitipon.","choice_b_en":"Dismiss everyone to go home and wait for official reports.","choice_b_fil":"Paalisin ang lahat upang umuwi at maghintay ng mga opisyal na ulat.","choice_c_en":"Start an immediate investigation into the cause of the fire.","choice_c_fil":"Simulan ang agarang imbestigasyon sa sanhi ng sunog.","choice_d_en":"Allow everyone to re-enter the building to retrieve belongings.","choice_d_fil":"Pahintulutan ang lahat na muling pumasok sa gusali upang kunin ang mga gamit."},{"number":11,"competency":"decision_making","correct_answer":"B","question_en":"During the evacuation, Barangay Kagawad Maria observes a group of seniors struggling near a partially obstructed exit. What is her most appropriate action?","question_fil":"Sa panahon ng paglikas, napansin ni Barangay Kagawad Maria ang isang grupo ng mga nakatatanda na nahihirapan malapit sa isang bahagyang nakaharang na labasan. Ano ang pinakaangkop niyang aksyon?","explanation_en":"LGU personnel should prioritize assisting vulnerable groups and, if safe, remove immediate obstructions to facilitate their exit.","explanation_fil":"Dapat unahin ng mga tauhan ng LGU ang pagtulong sa mga mahihinang grupo at, kung ligtas, alisin ang mga agarang harang upang mapadali ang kanilang paglabas.","choice_a_en":"Direct them to an alternative exit which might be further away.","choice_a_fil":"Idirekta sila sa isang alternatibong labasan na maaaring mas malayo.","choice_b_en":"Clear the obstruction quickly if safe, and actively assist them out.","choice_b_fil":"Alisin kaagad ang harang kung ligtas, at aktibong tulungan silang lumabas.","choice_c_en":"Tell them to hurry up or they will be left behind.","choice_c_fil":"Sabihin sa kanila na magmadali kung hindi ay maiiwan sila.","choice_d_en":"Focus on guiding other able-bodied individuals first.","choice_d_fil":"Magpokus muna sa paggabay sa iba pang may kakayahang indibidwal."},{"number":10,"competency":"safety_awareness","correct_answer":"B","question_en":"Why is it crucial to regularly inspect and maintain electrical systems, such as air conditioning units and power strips, in public facilities?","question_fil":"Bakit mahalaga ang regular na pag-inspeksyon at pagpapanatili ng mga sistemang elektrikal, tulad ng mga air conditioning unit at power strip, sa mga pampublikong pasilidad?","explanation_en":"Regular maintenance and inspection are key fire prevention practices, especially for electrical systems, to mitigate risks of shorts and fires.","explanation_fil":"Ang regular na pagpapanatili at inspeksyon ay mga pangunahing kasanayan sa pag-iwas sa sunog, lalo na para sa mga sistemang elektrikal, upang mabawasan ang panganib ng mga short circuit at sunog.","choice_a_en":"To meet aesthetic standards of the facility.","choice_a_fil":"Upang matugunan ang aesthetic standards ng pasilidad.","choice_b_en":"To prevent electrical overloads and potential fire incidents.","choice_b_fil":"Upang maiwasan ang electrical overloads at posibleng insidente ng sunog.","choice_c_en":"To keep utility bills low.","choice_c_fil":"Upang panatilihing mababa ang mga bayarin sa utility.","choice_d_en":"To extend the lifespan of the equipment.","choice_d_fil":"Upang pahabain ang buhay ng kagamitan."},{"number":4,"competency":"emergency_response","correct_answer":"A","question_en":"Considering the fire originated from an electrical source (air conditioning unit), which type of fire extinguisher would be most appropriate to attempt initial suppression, if it were deemed safe to do so?","question_fil":"Isinasaalang-alang na ang sunog ay nagmula sa isang electrical na pinagmulan (air conditioning unit), anong uri ng fire extinguisher ang pinakaangkop na gamitin para sa paunang pagsugpo, kung ito ay itinuring na ligtas gawin?","explanation_en":"Electrical fires are Class C fires. Water and foam are conductive and dangerous for electrical fires. CO2 or dry chemical extinguishers are suitable for Class C fires.","explanation_fil":"Ang mga sunog na electrical ay Klase C. Ang tubig at foam ay conductive at mapanganib para sa mga electrical na sunog. Ang CO2 o dry chemical extinguishers ay angkop para sa mga sunog na Klase C.","choice_a_en":"Carbon Dioxide (CO2) or Dry Chemical (Class B and C)","choice_a_fil":"Carbon Dioxide (CO2) o Dry Chemical (Klase B at C)","choice_b_en":"Foam extinguisher (Class A and B)","choice_b_fil":"Foam extinguisher (Klase A at B)","choice_c_en":"Water extinguisher (Class A)","choice_c_fil":"Water extinguisher (Klase A)","choice_d_en":"Wet Chemical extinguisher (Class K)","choice_d_fil":"Wet Chemical extinguisher (Klase K)"},{"number":9,"competency":"knowledge","correct_answer":"B","question_en":"The \'PASS\' technique for operating a fire extinguisher stands for:","question_fil":"Ang teknik na \'PASS\' para sa paggamit ng fire extinguisher ay nangangahulugang:","explanation_en":"This is the standard acronym for operating a fire extinguisher, as covered in fire safety training modules.","explanation_fil":"Ito ang pamantayang acronym para sa paggamit ng fire extinguisher, gaya ng sakop sa mga modyul ng pagsasanay sa kaligtasan sa sunog.","choice_a_en":"Pump, Alert, Secure, Stand","choice_a_fil":"Pump (Pump), I-alert (Alert), I-secure (Secure), Tumayo (Stand)","choice_b_en":"Pull, Aim, Squeeze, Sweep","choice_b_fil":"Hilahin (Pull), Itutok (Aim), Pigain (Squeeze), Walisin (Sweep)","choice_c_en":"Point, Advance, Shift, Suppress","choice_c_fil":"Ituro (Point), Umusad (Advance), Lumipat (Shift), Sugpuin (Suppress)","choice_d_en":"Press, Activate, Stop, Spray","choice_d_fil":"Pindutin (Press), I-aktibo (Activate), Huminto (Stop), I-spray (Spray)"},{"number":2,"competency":"safety_awareness","correct_answer":"D","question_en":"In the scenario, the presence of old chairs and tables partially obstructing the hall\'s exits primarily poses a risk by:","question_fil":"Sa sitwasyon, ang pagkakaroon ng mga lumang upuan at mesa na bahagyang nakaharang sa mga labasan ng bulwagan ay pangunahing nagdudulot ng panganib sa pamamagitan ng:","explanation_en":"Obstructions near exits directly impede the flow of people during an emergency evacuation, increasing danger and slowing response.","explanation_fil":"Ang mga harang malapit sa mga labasan ay direktang humahadlang sa pagdaloy ng mga tao sa panahon ng emerhensiyang paglikas, na nagpapataas ng panganib at nagpapabagal sa pagtugon.","choice_a_en":"Making the hall look untidy.","choice_a_fil":"Pagpapamukha sa bulwagan na hindi maayos.","choice_b_en":"Attracting pests and insects.","choice_b_fil":"Pag-akit ng mga peste at insekto.","choice_c_en":"Causing electrical overloads.","choice_c_fil":"Pagdulot ng electrical overloads.","choice_d_en":"Hindering efficient evacuation.","choice_d_fil":"Paghadlang sa epektibong paglikas."},{"number":1,"competency":"knowledge","correct_answer":"A","question_en":"What is one of the most common hazards that can cause injuries, loss of life, and damage to property, as introduced in the Fire Safety module?","question_fil":"Ano ang isa sa mga pinakakaraniwang peligro na maaaring magdulot ng mga pinsala, pagkawala ng buhay, at pinsala sa ari-arian, ayon sa ipinakilala sa modyul ng Kaligtasan sa Sunog?","explanation_en":"Lesson 1, \'Introduction to Fire Safety,\' states that fire is one of the most common hazards.","explanation_fil":"Ang Aralin 1, \'Panimula sa Kaligtasan sa Sunog,\' ay nagsasaad na ang sunog ay isa sa mga pinakakaraniwang peligro.","choice_a_en":"Fires","choice_a_fil":"Mga Sunog","choice_b_en":"Typhoons","choice_b_fil":"Mga Bagyo","choice_c_en":"Landslides","choice_c_fil":"Mga Pagguho ng Lupa","choice_d_en":"Earthquakes","choice_d_fil":"Mga Lindol"}]', '[]', 0, '2026-06-28 05:38:02', '2026-06-28 05:38:09', '2026-06-28 05:38:09');
