REPLACE INTO `lesson_resources` (`id`, `training_content_id`, `title`, `resource_type`, `body`, `file_path`, `external_url`, `sort_order`, `ai_processed_text`, `ai_processing_status`, `ai_processing_error`, `ai_processed_at`, `created_at`, `updated_at`) VALUES
	(1, 6, 'Lesson 1: Introduction to Fire Safety', 'text', 'Fire is one of the most common hazards that can cause injuries, loss of life, and damage to property. This lesson introduces fire safety fundamentals, the Fire Triangle (heat, fuel, oxygen), and personal responsibilities for preventing fire incidents at home, work, and in the community.', NULL, NULL, 1, NULL, NULL, NULL, NULL, '2026-06-27 07:14:59', '2026-07-09 04:19:46'),
	(2, 7, 'Lesson 2 : Common Causes of Fire', 'youtube', NULL, NULL, 'https://www.youtube.com/watch?v=b6eGSTiYkgY', 1, NULL, NULL, NULL, NULL, '2026-06-27 07:21:07', '2026-06-27 08:14:51'),
	(3, 8, 'Lesson 3: Fire Prevention', 'pdf', NULL, '/storage/training-contents/pdf/G0RJFujvtIfnXTmX9Coh7YcUXc64BRsqIT85G93M.pdf', NULL, 1, NULL, NULL, NULL, NULL, '2026-06-27 08:13:02', '2026-06-27 08:13:02'),
	(4, 9, 'Introduction', 'text', 'Learn how fires start, spread, and behave in residential and community settings.', NULL, NULL, 1, NULL, NULL, NULL, NULL, '2026-07-09 04:19:46', '2026-07-09 04:19:46'),
	(5, 10, 'Evacuation Guide', 'text', 'Step-by-step guide for safe evacuation during fire emergencies.', NULL, NULL, 1, NULL, NULL, NULL, NULL, '2026-07-09 04:19:46', '2026-07-09 04:19:46'),
	(6, 11, 'Flood Advisory Basics', 'text', 'How to interpret PAGASA and local flood warning levels.', NULL, NULL, 1, NULL, NULL, NULL, NULL, '2026-07-09 04:19:46', '2026-07-09 04:19:46'),
	(7, 12, 'Earthquake Drill Steps', 'text', 'Practice the correct drop-cover-hold technique during seismic events.', NULL, NULL, 1, NULL, NULL, NULL, NULL, '2026-07-09 04:19:46', '2026-07-09 04:19:46');
