	(1, 'Quarterly Fire Drill - Barangay Hall', 'Fire', 'Simulation of a fire incident in the barangay hall with full evacuation drill.', 'Drill', 'ended', '2026-07-04', '09:00:00', '11:00:00', 0, NULL, 'Barangay Hall', NULL, 'Main Building', 'Ground Floor', 'Assembly point at covered court.', 'Wheelchair access available at side entrance.', 'Front main exit, side exit near records room.', 'Records room, pantry area.', 'Covered court across the street.', 1, NULL, NULL, NULL, 4, 1, '["JB"]', NULL, '["LGU_ADMIN","LGU_TRAINER","PARTICIPANT"]', NULL, 80, NULL, 1, 0, 1, 'FIREDRILL', '[]', 'Wear closed shoes and follow marshal instructions.', 'Simulated smoke may affect people with respiratory conditions.', 'Closed shoes; optional face mask.', '["Briefing","Alarm","Evacuation","Debriefing"]', '[]', 'Ensure all zones are checked and accounted for during debrief.', 1, 0, '[]', 1, 3, NULL, NULL, '2026-06-27 12:04:21', '2026-07-09 04:20:07', NULL, NULL, NULL, NULL, NULL, NULL),
	(2, 'Completed Earthquake Drill - Municipal Hall', 'Earthquake', 'Previously conducted earthquake drill to showcase completed event state.', 'Drill', 'completed', '2026-06-17', '10:00:00', '12:00:00', 0, NULL, 'Municipal Hall', NULL, 'Main Building', 'Second Floor', 'Assembly point at open parking lot.', 'Elevator and ramp available.', 'Main stairwell, emergency back exit.', 'Glass-front offices, storage areas.', 'Open parking lot behind the building.', 1, 1, NULL, NULL, 6, 1, '["JB"]', NULL, '["LGU_ADMIN","LGU_TRAINER","PARTICIPANT"]', NULL, 120, NULL, 1, 0, 1, 'EQUAKE2026', '[]', 'Follow drop-cover-hold protocol and move calmly to assembly area.', 'Falling objects during simulated shaking.', 'Closed shoes; optional hard hat for facilitators.', '["Briefing","Shaking Simulation","Evacuation","Headcount","Debriefing"]', '[]', 'Emphasize calm evacuation and account for all staff.', 1, 0, '[]', 1, 1, NULL, NULL, '2026-06-27 12:04:21', '2026-07-09 04:19:46', NULL, NULL, NULL, NULL, NULL, NULL);
