REPLACE INTO `training_modules` (`id`, `title`, `short_description`, `description`, `learning_objectives`, `estimated_duration_minutes`, `recommended_audience`, `thumbnail_path`, `difficulty`, `category`, `related_hazard`, `delivery_method`, `target_audience`, `status`, `visibility`, `owner_id`, `lead_qualified_trainer_id`, `assigned_qualified_trainer_ids`, `lead_trainer_id`, `trainer_availability`, `available_training_sessions`, `created_at`, `updated_at`, `deleted_at`) VALUES
	(5, 'Fire Safety and Emergency Response', 'This training module equips participants with the fundamental knowledge and practical skills needed to prevent, respond to, and safely evacuate during fire-related emergencies. Participants will learn fire prevention strategies, the proper use of fire extinguishers, emergency response procedures, and evacuation protocols applicable in homes, schools, workplaces, and government facilities.', 'This training module equips participants with the fundamental knowledge and practical skills needed to prevent, respond to, and safely evacuate during fire-related emergencies. Participants will learn fire prevention strategies, the proper use of fire extinguishers, emergency response procedures, and evacuation protocols applicable in homes, schools, workplaces, and government facilities.', '["Understand the basic principles of fire safety.","Identify the common causes of fire incidents.","Apply effective fire prevention practices.","Recognize the different types of fire extinguishers and their appropriate uses.","Demonstrate the proper PASS technique when operating a fire extinguisher.","Follow the correct emergency response and evacuation procedures during a fire incident."]', 60, NULL, 'training-module-thumbnails/5J7rKA7ACj0w5MUNtedpX4WTnWai5jc5vEhf2dXu.png', 'Intermediate', 'Fire', 'Fire', 'in_person', '[]', 'published', 'all', 3, 5, '[5]', NULL, NULL, '[{"title":"Fire Safety and Emergency Response - Session 1","date":"2026-07-10","start_time":"13:28","end_time":"14:28","delivery_method":"online","venue":"","online_platform":"google_meet","meeting_link":"https:\\/\\/workspace.google.com\\/products\\/meet\\/?utm_source=google&utm_medium=cpc&utm_campaign=1713702-Workspace-DR-APAC-PH-en-Google-BKWS-BRO-Hybrid-Others&utm_content=c-Hybrid+%7C+BKWS+-+BRO+%7C+Txt-Meet-N\\/A+1-297900019805&utm_term=google%20meet&gclsrc=aw.ds&gad_source=1&gad_campaignid=18195926841&gclid=CjwKCAjw6rfSBhAqEiwA_yocpowGRU-kH0T63lHwhYliKozeMpjXCnZooY_sSJqjQQH1PH9aDKP9MRoCdkUQAvD_BwE","maximum_participants":30}]', '2026-06-27 15:11:29', '2026-07-09 04:28:56', NULL),
	(6, 'Basic Fire Safety and Evacuation', NULL, 'Foundational concepts on fire behavior, evacuation routes, and community response.', '["Identify common fire hazards in barangay settings.","Execute basic evacuation procedures.","Coordinate with local fire responders."]', 60, NULL, NULL, 'Beginner', 'Fire Safety', NULL, NULL, NULL, 'published', 'all', 1, NULL, NULL, NULL, NULL, NULL, '2026-07-09 04:19:46', '2026-07-09 04:20:46', '2026-07-09 04:20:46'),
	(7, 'Flood Preparedness and Early Warning', NULL, 'Training module focused on rainfall monitoring, flood mapping, and early warning communication.', '["Interpret simple weather and flood advisories.","Map flood-prone areas in the community.","Design an early warning notification flow."]', 90, NULL, NULL, 'Intermediate', 'Flood', NULL, NULL, NULL, 'published', 'all', 1, NULL, NULL, NULL, NULL, NULL, '2026-07-09 04:19:46', '2026-07-09 04:19:46', NULL),
	(8, 'Earthquake Drill and Evacuation', NULL, 'Scenario-based training on earthquake drills, drop-cover-hold, and evacuation to safe zones.', '["Perform drop-cover-hold correctly.","Identify safe evacuation routes and assembly points.","Coordinate with barangay disaster volunteers."]', 45, NULL, NULL, 'Intermediate', 'Earthquake', NULL, NULL, NULL, 'published', 'all', 1, NULL, NULL, NULL, NULL, NULL, '2026-07-09 04:19:46', '2026-07-09 04:19:46', NULL);
